// ── Numeric detection ────────────────────────────────────────────────────────

// Returns true only for strings that are entirely a valid finite number.
// Rejects values like "6wpi", "Infinity", "0xFF" that Number() would
// accept or partially parse.
function isNumericValue(v) {
  return /^\s*-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?\s*$/.test(v);
}

// ── Seeded random ────────────────────────────────────────────────────────────

function seededRandom(seed) {
  let s = seed;
  return () => {
    s = (s * 16807 + 0) % 2147483647;
    return s / 2147483647;
  };
}

// ── Example dataset (long format, used by group plot "Load example") ──
// Arabidopsis biomass × 3 genotypes × 3 treatments × 8 replicates = 72 rows.
// Effects are tuned so k=3 ANOVA + Tukey is meaningful, facet-by-Treatment works,
// and group colors / filters / renames all have something interesting to show.
function makeExamplePlantCSV() {
  const rng = seededRandom(42);
  // Box–Muller standard normal from the seeded uniform RNG.
  const norm = () => {
    const u = Math.max(rng(), 1e-9);
    const v = rng();
    return Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
  };
  const genotypes = [
    { name: "WT", base: 100 },
    { name: "abi4", base: 96 },
    { name: "oxSOS1", base: 128 },
  ];
  const treatments = [
    { name: "control", delta: 0, sd: 8 },
    { name: "drought", delta: -24, sd: 10 },
    { name: "salt", delta: -5, sd: 9 },
  ];
  const lines = ["Genotype,Treatment,Replicate,Biomass_mg"];
  for (const g of genotypes) {
    for (const t of treatments) {
      for (let r = 1; r <= 8; r++) {
        const v = g.base + t.delta + norm() * t.sd;
        lines.push(`${g.name},${t.name},${r},${v.toFixed(1)}`);
      }
    }
  }
  return lines.join("\n");
}

// ── Axis ticks ───────────────────────────────────────────────────────────────

function niceStep(range, approxN) {
  const rough = range / approxN;
  const mag = Math.pow(10, Math.floor(Math.log10(rough)));
  const nice = rough / mag;
  if (nice <= 1) return mag;
  if (nice <= 2) return 2 * mag;
  if (nice <= 5) return 5 * mag;
  return 10 * mag;
}
function makeTicks(min, max, approxN) {
  const step = niceStep(max - min || 1, approxN);
  const start = Math.ceil(min / step) * step;
  const ticks = [];
  for (let v = start; v <= max + step * 0.001; v += step) {
    const tick = parseFloat(v.toPrecision(10));
    if (tick <= max + step * 1e-9) ticks.push(tick);
  }
  return ticks;
}
function makeLogTicks(dataMin, dataMax, base) {
  if (!isFinite(dataMin) || dataMin <= 0) dataMin = base === 2 ? 0.5 : 0.1;
  if (!isFinite(dataMax) || dataMax <= dataMin) dataMax = dataMin * 1000;
  const logFn = base === 2 ? Math.log2 : base === 10 ? Math.log10 : Math.log;
  const logMin = Math.floor(logFn(dataMin));
  const logMax = Math.ceil(logFn(dataMax));
  const decades = logMax - logMin;
  const ticks = [];
  for (let exp = logMin; exp <= logMax; exp++) {
    const v = Math.pow(base, exp);
    if (v >= dataMin * 0.99 && v <= dataMax * 1.01) ticks.push({ value: v, major: true });
    if (base === 10) {
      const muls = [2, 3, 4, 5, 6, 7, 8, 9];
      for (const mul of muls) {
        const sv = mul * Math.pow(base, exp);
        if (sv >= dataMin * 0.99 && sv <= dataMax * 1.01) ticks.push({ value: sv, major: false });
      }
    } else if (base === 2 && decades <= 8) {
      const mid = Math.pow(base, exp) * 1.5;
      if (mid >= dataMin * 0.99 && mid <= dataMax * 1.01) ticks.push({ value: mid, major: false });
    }
  }
  ticks.sort((a, b) => a.value - b.value);
  return ticks;
}

// ── Separator detection ───────────────────────────────────────────────────────

function autoDetectSep(text, override = "") {
  if (override !== "") return override;
  const h = text.slice(0, 2000);
  const t = (h.match(/\t/g) || []).length,
    s = (h.match(/;/g) || []).length,
    c = (h.match(/,/g) || []).length;
  const b = Math.max(t, s, c);
  if (b === 0) return /\s+/;
  if (t === b) return "\t";
  if (s === b) return ";";
  return ",";
}

// ── Decimal comma fix ─────────────────────────────────────────────────────────

function fixDecimalCommas(text, sep) {
  // If the separator is a comma, commas in values are column delimiters — never decimal separators.
  // If sep is unknown, auto-detect: if commas dominate, treat them as column separators.
  const knownSep = sep || "";
  if (knownSep === ",") return { text, commaFixed: false, count: 0 };
  if (knownSep === "") {
    const h = text.slice(0, 2000);
    const t = (h.match(/\t/g) || []).length,
      s = (h.match(/;/g) || []).length,
      c = (h.match(/,/g) || []).length;
    if (c >= s && c >= t) return { text, commaFixed: false, count: 0 };
  }
  let count = 0;
  const fixed = text.replace(/(\d),(\d)/g, (_, a, b) => {
    count++;
    return `${a}.${b}`;
  });
  return { text: fixed, commaFixed: count > 0, count };
}

// ── Parsing helpers ───────────────────────────────────────────────────────────

function detectHeader(rows) {
  if (rows.length < 2) return true;
  const a = rows[0].filter((v) => !isNumericValue(v) && v.trim() !== "").length;
  const b = rows[1].filter((v) => !isNumericValue(v) && v.trim() !== "").length;
  if (a > b) return true;
  if (a === b && a > 0) {
    let reps = 0;
    for (let i = 1; i < Math.min(rows.length, 20); i++)
      for (let c = 0; c < rows[0].length; c++)
        if (rows[i][c] && rows[i][c].trim() === rows[0][c].trim()) reps++;
    return reps < rows[0].length;
  }
  return a > 0;
}

function parseRaw(text, sepOv = "") {
  const sep = autoDetectSep(text, sepOv);
  const lines = text
    .trim()
    .split(/\r?\n/)
    .filter((l) => l.trim() !== "");
  if (lines.length < 1) return { headers: [], rows: [], hasHeader: false };
  const all = lines.map((l) => l.split(sep).map((v) => v.trim().replace(/^"|"$/g, "")));
  if (all.length === 0) return { headers: [], rows: [], hasHeader: false };
  const mx = Math.max(...all.map((r) => r.length));
  const pad = all.map((r) => {
    while (r.length < mx) r.push("");
    return r;
  });
  const hh = detectHeader(pad);
  if (hh) return { headers: pad[0], rows: pad.slice(1), hasHeader: true };
  return { headers: pad[0].map((_, i) => `Col_${i + 1}`), rows: pad, hasHeader: false };
}

function guessColumnType(vals) {
  const ne = vals.filter((v) => v != null && v !== "");
  if (ne.length === 0) return "ignore";
  if (ne.filter((v) => isNumericValue(v)).length / ne.length > 0.8) return "value";
  const u = new Set(ne);
  if (u.size <= 20 && u.size < ne.length * 0.5) return "group";
  return "text";
}

function detectWideFormat(headers, rows) {
  if (headers.length < 2 || rows.length < 2) return false;
  const numericCols = headers.map((_, ci) => {
    const vals = rows.map((r) => r[ci]).filter((v) => v !== "");
    return vals.length > 0 && vals.filter((v) => isNumericValue(v)).length / vals.length > 0.8;
  });
  return numericCols.every(Boolean);
}

// Wide-matrix parser for heatmap-style data:
//   first row     = column labels (the leading cell is the row-label-column
//                   heading and may be blank or any token — we drop it)
//   first column  = row labels
//   everything else = numeric values (non-numeric cells become NaN and are
//                   counted in warnings.nonNumeric so the UI can surface them)
// Returns { rowLabels, colLabels, matrix, warnings } where matrix is a
// 2-D array shaped [rowLabels.length][colLabels.length].
function parseWideMatrix(text, sepOv = "") {
  const { headers, rows } = parseRaw(text, sepOv);
  if (headers.length < 2 || rows.length < 1) {
    return {
      rowLabels: [],
      colLabels: [],
      matrix: [],
      warnings: { nonNumeric: 0, emptyRows: 0, emptyCols: 0 },
    };
  }
  const colLabels = headers.slice(1);
  const rowLabels = [];
  const matrix = [];
  let nonNumeric = 0;
  rows.forEach((r) => {
    const label = r[0] == null ? "" : String(r[0]);
    const values = new Array(colLabels.length);
    for (let ci = 0; ci < colLabels.length; ci++) {
      const raw = r[ci + 1];
      if (raw == null || raw === "") {
        values[ci] = NaN;
      } else if (isNumericValue(raw)) {
        values[ci] = Number(raw);
      } else {
        values[ci] = NaN;
        nonNumeric++;
      }
    }
    rowLabels.push(label);
    matrix.push(values);
  });
  return { rowLabels, colLabels, matrix, warnings: { nonNumeric } };
}

// ── Unified data parsing ─────────────────────────────────────────────────────

function parseData(text, sepOv = "") {
  const sep = autoDetectSep(text, sepOv);
  const lines = text
    .trim()
    .split(/\r?\n/)
    .filter((l) => l.trim() !== "");
  if (lines.length < 2) return { headers: [], data: [], rawData: [] };
  const headers = lines[0].split(sep).map((h) => h.trim().replace(/^"|"$/g, ""));
  const nCols = headers.length;
  const data = [],
    rawData = [];
  for (let i = 1; i < lines.length; i++) {
    const rawVals = lines[i].split(sep).map((v) => v.trim().replace(/^"|"$/g, ""));
    while (rawVals.length < nCols) rawVals.push("");
    if (rawVals.every((v) => v === "")) continue;
    data.push(rawVals.map((s) => (isNumericValue(s) ? Number(s) : null)));
    rawData.push(rawVals);
  }
  return { headers, data, rawData };
}

function dataToColumns(data, nCols) {
  const columns = Array.from({ length: nCols }, () => []);
  for (const row of data) {
    for (let c = 0; c < nCols; c++) {
      if (row[c] != null) columns[c].push(row[c]);
    }
  }
  return columns;
}

// ── Wide / long format helpers ────────────────────────────────────────────────

function wideToLong(headers, rows) {
  const longRows = [];
  rows.forEach((r) => {
    headers.forEach((h, ci) => {
      if (r[ci] !== "" && isNumericValue(r[ci])) longRows.push([h, r[ci]]);
    });
  });
  return { headers: ["Group", "Value"], rows: longRows };
}

function reshapeWide(rows, gi, vi) {
  const g = {};
  rows.forEach((r) => {
    const k = r[gi] || "?";
    if (!g[k]) g[k] = [];
    g[k].push(r[vi]);
  });
  const vals = Object.values(g);
  if (vals.length === 0) return { headers: [], rows: [] };
  const mx = Math.max(...vals.map((v) => v.length));
  const names = Object.keys(g);
  const w = [];
  for (let i = 0; i < mx; i++) w.push(names.map((n) => (g[n][i] != null ? g[n][i] : "")));
  return { headers: names, rows: w };
}

// ── Set-membership parsing (Venn / UpSet) ─────────────────────────────────────

// Wide format: each column is one set, cells are item ids. Preserves the
// column order via Map so downstream colour/index assignment is deterministic.
function parseSetData(headers, rows) {
  const sets = new Map();
  for (let ci = 0; ci < headers.length; ci++) {
    const s = new Set();
    for (const r of rows) {
      const v = (r[ci] || "").trim();
      if (v) s.add(v);
    }
    if (s.size > 0) sets.set(headers[ci], s);
  }
  const setNames = [...sets.keys()];
  return { setNames, sets };
}

// Long format: exactly two columns — item id, set name. Pivots into the same
// {setNames, sets} shape as parseSetData. setNames are ordered by first
// appearance in the input. Throws if the table doesn't have exactly 2 columns.
function parseLongFormatSets(headers, rows) {
  if (!headers || headers.length !== 2) {
    throw new Error("Long format requires exactly 2 columns (item, set).");
  }
  const sets = new Map();
  for (const r of rows) {
    const item = (r[0] || "").trim();
    const setName = (r[1] || "").trim();
    if (!item || !setName) continue;
    if (!sets.has(setName)) sets.set(setName, new Set());
    sets.get(setName).add(item);
  }
  const setNames = [...sets.keys()];
  return { setNames, sets };
}

// ── Statistics ────────────────────────────────────────────────────────────────

function computeStats(arr) {
  const n = arr.length;
  if (n === 0) return null;
  const mean = arr.reduce((a, b) => a + b, 0) / n;
  const variance = arr.reduce((s, v) => s + (v - mean) ** 2, 0) / (n > 1 ? n - 1 : 1);
  const sd = Math.sqrt(variance);
  const sem = n > 1 ? sd / Math.sqrt(n) : 0;
  // 95% CI half-width (two-sided t-critical × SEM). Matches lineplot's per-x
  // CI at line 86. Falls back to 0 when n<2 or tinv is unavailable (shared.js
  // loads before stats.js, but this runs at call time when tinv is global).
  const ci95 = n > 1 && typeof tinv === "function" ? tinv(0.975, n - 1) * sem : 0;
  const sorted = [...arr].sort((a, b) => a - b);
  const min = sorted[0];
  const max = sorted[n - 1];
  const median = n % 2 === 0 ? (sorted[n / 2 - 1] + sorted[n / 2]) / 2 : sorted[Math.floor(n / 2)];
  return { mean, sd, sem, ci95, n, min, max, median };
}

function quartiles(arr) {
  const s = [...arr].sort((a, b) => a - b),
    n = s.length;
  if (n === 0) return null;
  const q = (p) => {
    const i = p * (n - 1),
      lo = Math.floor(i),
      hi = Math.min(Math.ceil(i), n - 1);
    return lo === hi ? s[lo] : s[lo] * (hi - i) + s[hi] * (i - lo);
  };
  const q1 = q(0.25),
    med = q(0.5),
    q3 = q(0.75),
    iqr = q3 - q1;
  return {
    min: s[0],
    max: s[n - 1],
    q1,
    med,
    q3,
    iqr,
    wLo: Math.min(s.find((v) => v >= q1 - 1.5 * iqr) ?? s[0], q1),
    wHi: Math.max([...s].reverse().find((v) => v <= q3 + 1.5 * iqr) ?? s[n - 1], q3),
    n,
  };
}

function kde(values, nPoints = 50) {
  const n = values.length;
  if (n === 0) return [];
  const sorted = [...values].sort((a, b) => a - b);
  const min = sorted[0],
    max = sorted[n - 1];
  const iqr = n >= 4 ? sorted[Math.floor(n * 0.75)] - sorted[Math.floor(n * 0.25)] : max - min;
  const mean = values.reduce((a, b) => a + b, 0) / n;
  const variance = values.reduce((s, v) => s + (v - mean) ** 2, 0) / n;
  const std = Math.sqrt(variance);
  const bw = 1.06 * Math.min(std, (iqr || 1) / 1.34) * n ** -0.2 || 1;
  const pad = bw * 2;
  const lo = min - pad,
    hi = max + pad;
  const step = (hi - lo) / (nPoints - 1);
  const pts = [];
  for (let i = 0; i < nPoints; i++) {
    const x = lo + i * step;
    let density = 0;
    for (let j = 0; j < n; j++) {
      const z = (x - values[j]) / bw;
      density += Math.exp(-0.5 * z * z);
    }
    density /= n * bw * Math.sqrt(2 * Math.PI);
    pts.push({ x, d: density });
  }
  return pts;
}

function computeGroupStats(groups) {
  return Object.entries(groups).map(([name, vals]) => {
    const nums = vals.filter((v) => v !== "" && isNumericValue(v)).map(Number);
    const stats = computeStats(nums);
    if (!stats)
      return { name, n: 0, mean: null, sd: null, sem: null, min: null, max: null, median: null };
    return { name, ...stats };
  });
}

// ── Download helpers ──────────────────────────────────────────────────────────

// Sanitize an arbitrary string into an SVG-safe id fragment so exported
// <g id="..."> values are valid NCNames and show up as readable group names
// in Inkscape's Objects panel / XML editor. Non-alphanumerics become hyphens,
// runs are collapsed, edges trimmed, and a leading digit is prefixed with "_".
function svgSafeId(s) {
  if (s == null) return "unnamed";
  const cleaned = String(s)
    .replace(/[^A-Za-z0-9_.-]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
  if (!cleaned) return "unnamed";
  return /^[A-Za-z_]/.test(cleaned) ? cleaned : "_" + cleaned;
}

function fileBaseName(fileName, fallback) {
  if (typeof fileName === "string" && fileName.trim()) return fileName.replace(/\.[^.]+$/, "");
  return fallback || "data";
}

function flashSaved(btn) {
  if (!btn) return;
  const original = btn.innerHTML;
  btn.innerHTML = "✓ Saved";
  btn.disabled = true;
  setTimeout(() => {
    btn.innerHTML = original;
    btn.disabled = false;
  }, 1500);
}

// Produce a standalone SVG string suitable for a file export.
//
// Two transformations vs the live DOM, both Inkscape workarounds:
//
//   1. Strip the root <svg> inline `style="max-width:100%;height:auto;..."`
//      (responsive-layout sugar that only makes sense inside an HTML flow;
//      Inkscape's CSS engine can collapse the computed viewport when it sees
//      `height: auto` on a root <svg>).
//
//   2. Strip every `shape-rendering="crispEdges"` attribute. This matters for
//      the heatmap, where the cells group carries crispEdges to keep browser
//      PNG rasterisation seamless. Inkscape ≥1.1 has a cairo-renderer bug
//      where crispEdges on a group containing thousands of small rects (esp.
//      sub-pixel-height ones like heatmap cells at 2 px tall) collapses the
//      whole group to default-fill (black). Our cell rects are already on
//      integer pixel coordinates via Math.round in the layout code, so
//      crispEdges is redundant for seam avoidance in the exported file — we
//      just drop it on export.
function serializeSvgForExport(svgEl) {
  const clone = svgEl.cloneNode(true);
  clone.removeAttribute("style");
  clone.querySelectorAll("[shape-rendering]").forEach((el) => {
    el.removeAttribute("shape-rendering");
  });
  return new XMLSerializer().serializeToString(clone);
}

function downloadSvg(svgEl, filename) {
  if (!svgEl) return;
  const svgStr = serializeSvgForExport(svgEl);
  const blob = new Blob([svgStr], { type: "image/svg+xml" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.style.display = "none";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}
function downloadPng(svgEl, filename, scale) {
  if (!svgEl) return;
  scale = scale || 2;
  const svgStr = serializeSvgForExport(svgEl);
  const vb = svgEl.getAttribute("viewBox");
  const parts = vb ? vb.split(/[\s,]+/) : [];
  const w = parts.length >= 4 ? parseFloat(parts[2]) : svgEl.clientWidth || 800;
  const h = parts.length >= 4 ? parseFloat(parts[3]) : svgEl.clientHeight || 600;
  const canvas = document.createElement("canvas");
  canvas.width = w * scale;
  canvas.height = h * scale;
  const ctx = canvas.getContext("2d");
  ctx.fillStyle = "#ffffff";
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  const img = new Image();
  const blob = new Blob([svgStr], { type: "image/svg+xml;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  img.onload = function () {
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    URL.revokeObjectURL(url);
    canvas.toBlob(function (pngBlob) {
      const pngUrl = URL.createObjectURL(pngBlob);
      const a = document.createElement("a");
      a.href = pngUrl;
      a.download = filename;
      a.style.display = "none";
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setTimeout(function () {
        URL.revokeObjectURL(pngUrl);
      }, 1000);
    }, "image/png");
  };
  img.src = url;
}
function downloadText(text, filename) {
  const blob = new Blob([text], { type: "text/plain" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.style.display = "none";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function downloadCsv(headers, rows, filename) {
  const lines = [
    headers.join(","),
    ...rows.map((r) => r.map((v) => `"${String(v).replace(/"/g, '""')}"`).join(",")),
  ];
  const blob = new Blob([lines.join("\n")], { type: "text/csv" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.style.display = "none";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

// ──────────────────────────────────────────────────────────────────
// stats.js
// ──────────────────────────────────────────────────────────────────
// stats.js — statistical distribution functions and tests.
//
// Loaded as a plain <script> tag in tool HTML (like shared.js /
// shared-components.js); exposes everything as globals. Tools and tests
// consume these names without imports.
//
// Layout:
//   1. Distribution functions       — normal, gamma, beta, t, F, chi-square,
//                                     noncentral t/F/chi-square
//   2. Generic helpers              — bisect
//   3. Sample helpers               — mean, variance, sd (sample), rank-with-ties
//   4. Normality tests              — Shapiro-Wilk (Royston 1995, AS R94)
//
// All new functions are benchmarked against R output in tests/stats.test.js
// with the same ±0.5% tolerance bar used for the power tool.

// ── 1. Distribution functions ───────────────────────────────────────────────

// Normal CDF — Abramowitz & Stegun 26.2.17 (max error 7.5e-8)
function normcdf(x) {
  if (x === 0) return 0.5;
  const t = 1 / (1 + 0.2316419 * Math.abs(x));
  const d = 0.3989422804014327; // 1/sqrt(2*pi)
  const poly =
    t *
    (0.31938153 + t * (-0.356563782 + t * (1.781477937 + t * (-1.821255978 + t * 1.330274429))));
  const p = 1 - d * Math.exp(-0.5 * x * x) * poly;
  return x > 0 ? p : 1 - p;
}

// Inverse normal CDF — Peter Acklam's rational approximation (max error 1.15e-9)
function norminv(p) {
  if (p <= 0) return -Infinity;
  if (p >= 1) return Infinity;
  if (p === 0.5) return 0;
  const a = [
    -3.969683028665376e1, 2.209460984245205e2, -2.759285104469687e2, 1.38357751867269e2,
    -3.066479806614716e1, 2.506628277459239,
  ];
  const b = [
    -5.447609879822406e1, 1.615858368580409e2, -1.556989798598866e2, 6.680131188771972e1,
    -1.328068155288572e1,
  ];
  const c = [
    -7.784894002430293e-3, -3.223964580411365e-1, -2.400758277161838, -2.549732539343734,
    4.374664141464968, 2.938163982698783,
  ];
  const d = [7.784695709041462e-3, 3.224671290700398e-1, 2.445134137142996, 3.754408661907416];
  const pLow = 0.02425,
    pHigh = 1 - pLow;
  let q, r;
  if (p < pLow) {
    q = Math.sqrt(-2 * Math.log(p));
    return (
      (((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q + c[5]) /
      ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1)
    );
  }
  if (p <= pHigh) {
    q = p - 0.5;
    r = q * q;
    return (
      ((((((a[0] * r + a[1]) * r + a[2]) * r + a[3]) * r + a[4]) * r + a[5]) * q) /
      (((((b[0] * r + b[1]) * r + b[2]) * r + b[3]) * r + b[4]) * r + 1)
    );
  }
  q = Math.sqrt(-2 * Math.log(1 - p));
  return (
    -(((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q + c[5]) /
    ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1)
  );
}

// Log gamma — Lanczos approximation
function gammaln(x) {
  const g = 7;
  const coef = [
    0.99999999999980993, 676.5203681218851, -1259.1392167224028, 771.32342877765313,
    -176.61502916214059, 12.507343278686905, -0.13857109526572012, 9.9843695780195716e-6,
    1.5056327351493116e-7,
  ];
  if (x < 0.5) return Math.log(Math.PI / Math.sin(Math.PI * x)) - gammaln(1 - x);
  x -= 1;
  let a = coef[0];
  const t = x + g + 0.5;
  for (let i = 1; i < g + 2; i++) a += coef[i] / (x + i);
  return 0.5 * Math.log(2 * Math.PI) + (x + 0.5) * Math.log(t) - t + Math.log(a);
}

// Regularized incomplete beta function I_x(a, b) via continued fraction
function betai(a, b, x) {
  if (x < 0 || x > 1) return 0;
  if (x === 0) return 0;
  if (x === 1) return 1;
  const lnBeta = gammaln(a) + gammaln(b) - gammaln(a + b);
  const front = Math.exp(Math.log(x) * a + Math.log(1 - x) * b - lnBeta);
  if (x < (a + 1) / (a + b + 2)) {
    return (front * betacf(a, b, x)) / a;
  }
  return 1 - (front * betacf(b, a, 1 - x)) / b;
}

// Continued fraction for incomplete beta (Lentz's method)
function betacf(a, b, x) {
  const maxIter = 200,
    eps = 3e-14;
  const qab = a + b,
    qap = a + 1,
    qam = a - 1;
  let c = 1,
    d = 1 - (qab * x) / qap;
  if (Math.abs(d) < 1e-30) d = 1e-30;
  d = 1 / d;
  let h = d;
  for (let m = 1; m <= maxIter; m++) {
    const m2 = 2 * m;
    let aa = (m * (b - m) * x) / ((qam + m2) * (a + m2));
    d = 1 + aa * d;
    if (Math.abs(d) < 1e-30) d = 1e-30;
    d = 1 / d;
    c = 1 + aa / c;
    if (Math.abs(c) < 1e-30) c = 1e-30;
    h *= d * c;
    aa = (-(a + m) * (qab + m) * x) / ((a + m2) * (qap + m2));
    d = 1 + aa * d;
    if (Math.abs(d) < 1e-30) d = 1e-30;
    d = 1 / d;
    c = 1 + aa / c;
    if (Math.abs(c) < 1e-30) c = 1e-30;
    const del = d * c;
    h *= del;
    if (Math.abs(del - 1) < eps) break;
  }
  return h;
}

// Regularized incomplete gamma function P(a, x) — series expansion
function gammainc(a, x) {
  if (x < 0) return 0;
  if (x === 0) return 0;
  if (x > a + 1) return 1 - gammainc_upper(a, x);
  // Series converges in ~O(√a) steps when x ≈ a (Poisson-like concentration
  // around n ≈ x−a with width √a). A fixed 200-step cap silently truncated
  // large-a calls; scale with √a so chi2cdf / ptukey stay accurate at huge df.
  const maxIter = Math.max(200, Math.ceil(20 * Math.sqrt(a + 1)));
  let sum = 1 / a,
    term = 1 / a;
  for (let n = 1; n < maxIter; n++) {
    term *= x / (a + n);
    sum += term;
    if (Math.abs(term) < Math.abs(sum) * 3e-14) break;
  }
  return sum * Math.exp(-x + a * Math.log(x) - gammaln(a));
}

// Upper regularized incomplete gamma Q(a,x) = 1 - P(a,x) via continued fraction
function gammainc_upper(a, x) {
  let f = x + 1 - a,
    c = 1 / 1e-30,
    d = 1 / f,
    h = d;
  const maxIter = Math.max(200, Math.ceil(20 * Math.sqrt(a + 1)));
  for (let i = 1; i < maxIter; i++) {
    const an = -i * (i - a);
    const bn = x + 2 * i + 1 - a;
    d = bn + an * d;
    if (Math.abs(d) < 1e-30) d = 1e-30;
    d = 1 / d;
    c = bn + an / c;
    if (Math.abs(c) < 1e-30) c = 1e-30;
    const del = d * c;
    h *= del;
    if (Math.abs(del - 1) < 3e-14) break;
  }
  return Math.exp(-x + a * Math.log(x) - gammaln(a)) * h;
}

// t-distribution CDF
function tcdf(t, df) {
  const x = df / (df + t * t);
  const p = 0.5 * betai(df / 2, 0.5, x);
  return t >= 0 ? 1 - p : p;
}

// t-distribution PDF (computed in log space, used by tinv Newton-Raphson)
function tpdf(x, df) {
  const logpdf =
    gammaln((df + 1) / 2) -
    gammaln(df / 2) -
    0.5 * Math.log(Math.PI * df) -
    ((df + 1) / 2) * Math.log(1 + (x * x) / df);
  return Math.exp(logpdf);
}

// Inverse t CDF.
// Strategy:
//   • df = 1 and df = 2 have closed forms — use them directly.
//   • df ≥ 3: Newton-Raphson seeded with a Cornish-Fisher correction to the
//     normal quantile, with a damped step and a bisection fallback if Newton
//     fails to converge. Bracket bounds expand outward (doubling) to handle
//     heavy-tailed cases where |t| can exceed hundreds or thousands at
//     extreme p (e.g. qt(1e-10, 5) ≈ −157).
//   • Work in the left tail (leftP ≤ 0.5) and flip sign at the end, so that
//     inputs like p = 1 − 1e-15 don't suffer catastrophic cancellation.
function tinv(p, df) {
  if (p <= 0) return -Infinity;
  if (p >= 1) return Infinity;
  if (p === 0.5) return 0;

  const upper = p > 0.5;
  const leftP = upper ? 1 - p : p;

  let tLeft;

  if (df === 1) {
    // Cauchy: F⁻¹(u) = tan(π(u − 0.5)) = −cot(π·u).
    tLeft = -1 / Math.tan(Math.PI * leftP);
  } else if (df === 2) {
    // Closed form: t = (2u−1) / √(2u(1−u)).
    tLeft = (2 * leftP - 1) / Math.sqrt(2 * leftP * (1 - leftP));
  } else {
    // Cornish-Fisher seed: first-order correction to the normal quantile.
    const z = norminv(leftP);
    let x = z + (z * (z * z + 1)) / (4 * df);

    let converged = false;
    for (let i = 0; i < 60; i++) {
      const cdf = tcdf(x, df);
      const pdf = tpdf(x, df);
      if (!Number.isFinite(cdf) || !(pdf > 0)) break;
      let step = (cdf - leftP) / pdf;
      // Damp the step so we can't jump past a flat tail where PDF → 0.
      const cap = Math.abs(x) + 1;
      if (step > cap) step = cap;
      else if (step < -cap) step = -cap;
      x -= step;
      if (Math.abs(step) < 1e-13 * (Math.abs(x) + 1)) {
        converged = true;
        break;
      }
    }

    if (converged && Number.isFinite(x)) {
      tLeft = x;
    } else {
      // Bisection fallback: expand the lower bound until leftP is bracketed.
      let lo = -1;
      const hi = 0;
      for (let i = 0; i < 4000 && tcdf(lo, df) > leftP; i++) lo *= 2;
      let a = lo,
        b = hi;
      for (let i = 0; i < 200; i++) {
        const mid = (a + b) / 2;
        if (tcdf(mid, df) < leftP) a = mid;
        else b = mid;
        if (b - a < 1e-12 * (Math.abs(a) + 1)) break;
      }
      tLeft = (a + b) / 2;
    }
  }

  return upper ? -tLeft : tLeft;
}

// F-distribution CDF
function fcdf(f, d1, d2) {
  if (f <= 0) return 0;
  return betai(d1 / 2, d2 / 2, (d1 * f) / (d1 * f + d2));
}

// Chi-square CDF
function chi2cdf(x, k) {
  if (x <= 0) return 0;
  return gammainc(k / 2, x / 2);
}

// Chi-square PDF — used as the Newton derivative in chi2inv. Built in log
// space to avoid overflow at large k or tiny x.
function chi2pdf(x, k) {
  if (x <= 0) return 0;
  const halfK = k / 2;
  return Math.exp((halfK - 1) * Math.log(x) - x / 2 - halfK * Math.log(2) - gammaln(halfK));
}

// Inverse chi-square CDF — Newton-Raphson on the central body, bisection
// fallback for the saturated tails where the χ² CDF derivative collapses
// to ~10⁻¹² and Newton overshoots wildly. The historical implementation was
// pure bisection with a doubling upper bound (~50 iterations for 1e-10
// tolerance); this version is much faster on typical inputs while remaining
// correct on the tails. Uses the Wilson-Hilferty cubic-normal approximation
// (X/k)^(1/3) ≈ N(1 − 2/(9k), 2/(9k)) to seed both Newton and the bracket.
function chi2inv(p, k) {
  if (p <= 0) return 0;
  if (p >= 1) return Infinity;
  if (k <= 0) return NaN;
  const z = norminv(p);
  const h = 2 / (9 * k);
  let x = k * Math.pow(1 - h + z * Math.sqrt(h), 3);
  if (!(x > 0)) x = Math.max(1e-6, k * 0.01);
  // Newton inside a wide guard: only accept iterations that stay positive
  // and don't exceed twice the current point. If Newton makes <10⁻¹² PDF
  // (deep in the saturated tail) or the step would leave the guard, drop
  // straight to bisection.
  for (let i = 0; i < 30; i++) {
    const f = chi2cdf(x, k) - p;
    if (Math.abs(f) < 1e-12) return x;
    const fp = chi2pdf(x, k);
    if (!(fp > 1e-12)) break;
    const step = f / fp;
    const xNew = x - step;
    if (!(xNew > 0) || xNew > 2 * x || xNew < x / 2) break;
    if (Math.abs(xNew - x) < 1e-12 * Math.max(1, x)) return xNew;
    x = xNew;
  }
  // Bisection fallback. Use WH seed to set a tight initial bracket; expand
  // by doubling if it doesn't cover p (bisect itself refuses unbracketed
  // targets, so this guarantees progress).
  let lo = 0,
    hi = Math.max(x * 2, k + 10 * Math.sqrt(2 * k));
  for (let i = 0; i < 40 && chi2cdf(hi, k) < p; i++) hi *= 2;
  return bisect((q) => chi2cdf(q, k), p, lo, hi, 1e-10);
}

// Gauss-Legendre quadrature nodes and weights (computed once, cached)
let _glCache;
function _gaussLegendre(n) {
  if (_glCache && _glCache.n === n) return _glCache;
  const nodes = new Array(n),
    weights = new Array(n);
  for (let i = 0; i < Math.ceil(n / 2); i++) {
    let x = Math.cos((Math.PI * (i + 0.75)) / (n + 0.5));
    for (let it = 0; it < 100; it++) {
      let pm1 = 1,
        p = x;
      for (let j = 2; j <= n; j++) {
        const pp = ((2 * j - 1) * x * p - (j - 1) * pm1) / j;
        pm1 = p;
        p = pp;
      }
      const dp = (n * (x * p - pm1)) / (x * x - 1);
      const dx = p / dp;
      x -= dx;
      if (Math.abs(dx) < 1e-15) break;
    }
    let pm1 = 1,
      p = x;
    for (let j = 2; j <= n; j++) {
      const pp = ((2 * j - 1) * x * p - (j - 1) * pm1) / j;
      pm1 = p;
      p = pp;
    }
    const dp = (n * (x * p - pm1)) / (x * x - 1);
    const w = 2 / ((1 - x * x) * dp * dp);
    nodes[i] = -x;
    nodes[n - 1 - i] = x;
    weights[i] = w;
    weights[n - 1 - i] = w;
  }
  return (_glCache = { nodes, weights, n });
}

// Noncentral t CDF — Gauss-Legendre quadrature of chi-square mixture.
// P(T ≤ t | ν, δ) = ∫₀^∞ Φ(t√(s/ν) − δ) · f_χ²(s; ν) ds
// Substitution u = √s removes density singularity for small ν, giving:
// = ∫₀^∞ Φ(tu/√ν − δ) · 2u^{ν−1} e^{−u²/2} / (2^{ν/2} Γ(ν/2)) du
function nctcdf(t, df, delta) {
  if (Math.abs(delta) < 1e-14) return tcdf(t, df);
  const halfDf = df / 2;
  const logC = halfDf * Math.log(2) + gammaln(halfDf);
  const sqrtDf = Math.sqrt(df);
  const uLo = Math.max(0, sqrtDf - 8);
  const uHi = sqrtDf + 8;
  const gl = _gaussLegendre(48);
  const half = (uHi - uLo) / 2,
    mid = (uHi + uLo) / 2;
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const u = mid + half * gl.nodes[i];
    if (u <= 0) continue;
    const logH = Math.log(2) + (df - 1) * Math.log(u) - (u * u) / 2 - logC;
    sum += half * gl.weights[i] * normcdf((t * u) / sqrtDf - delta) * Math.exp(logH);
  }
  return Math.max(0, Math.min(1, sum));
}

// Noncentral F survival P(F' > f) — Poisson mixture
// F' = (χ²_{d1+2J}/d1) / (χ²_{d2}/d2), J~Poisson(λ/2)
// P(F'>f) = Σ_j P(J=j) × P(F(d1+2j, d2) > f × d1/(d1+2j))
// Starts at Poisson mode to avoid underflow for large λ.
function ncf_sf(f, d1, d2, lambda) {
  if (f <= 0) return 1;
  if (lambda <= 0) return 1 - fcdf(f, d1, d2);
  const halfLam = lambda / 2;

  // Large-λ short circuit: the Poisson mass around the mode has width
  // σ = √(λ/2), so a fixed 500-step window leaves most of the mass
  // unaccounted for when λ is huge. In that regime, P(F'>f) is either
  // ≈ 1 or ≈ 0 for f outside a few σ of the NCF mean — use closed-form
  // mean / variance of the NCF (valid for d2 > 4) and short-circuit via
  // normal approximation when f is clearly in the far tail. Without this,
  // power-analysis sample-size solvers probe huge n values (e.g. via
  // bisect up to hi=100000) and get misleading truncated-sum answers,
  // breaking the monotonic-in-n assumption the solver depends on.
  if (halfLam > 500 && d2 > 4) {
    const mean = (d2 / (d2 - 2)) * ((d1 + lambda) / d1);
    const v =
      (2 *
        Math.pow(d2 / (d2 - 2), 2) *
        ((d1 + lambda) * (d1 + lambda) + (d1 + 2 * lambda) * (d2 - 2))) /
      (d1 * d1 * (d2 - 4));
    const sd = Math.sqrt(v);
    const z = (f - mean) / sd;
    if (z < -6) return 1;
    if (z > 6) return 0;
  }

  const jMode = Math.max(0, Math.floor(halfLam));
  // Widen the Poisson window for larger λ so we cover ±8σ of the mass.
  const maxSteps = Math.max(500, Math.ceil(8 * Math.sqrt(halfLam + 1)));

  function sfTerm(j) {
    const d1j = d1 + 2 * j;
    return 1 - fcdf((f * d1) / d1j, d1j, d2);
  }

  let logPMode = -halfLam + (jMode > 0 ? jMode * Math.log(halfLam) - gammaln(jMode + 1) : 0);
  let pTerm = Math.exp(logPMode);
  let sum = pTerm * sfTerm(jMode);

  let pUp = pTerm;
  for (let j = jMode + 1; j < jMode + maxSteps; j++) {
    pUp *= halfLam / j;
    const contrib = pUp * sfTerm(j);
    sum += contrib;
    if (j - jMode > 10 && pUp < 1e-14) break;
  }

  let pDown = pTerm;
  for (let j = jMode - 1; j >= 0 && jMode - j < maxSteps; j--) {
    pDown *= (j + 1) / halfLam;
    const contrib = pDown * sfTerm(j);
    sum += contrib;
    if (jMode - j > 10 && pDown < 1e-14) break;
  }

  return Math.min(1, Math.max(0, sum));
}

// Noncentral chi-square CDF — Poisson mixture (starts at mode to avoid underflow)
function ncchi2cdf(x, k, lambda) {
  if (x <= 0) return 0;
  if (lambda <= 0) return chi2cdf(x, k);
  const halfLam = lambda / 2;
  // Large-λ short circuit: use normal approximation for the far tails.
  // Noncentral χ² has mean k+λ and variance 2(k+2λ); a |z|>6 tail is < 1e-9.
  if (halfLam > 500) {
    const mean = k + lambda;
    const sd = Math.sqrt(2 * (k + 2 * lambda));
    const z = (x - mean) / sd;
    if (z < -6) return 0;
    if (z > 6) return 1;
  }
  const jMode = Math.max(0, Math.floor(halfLam));
  // Poisson mixture width is √λ/2; widen the scan window with √halfLam so huge
  // λ doesn't silently truncate the sum (mirrors the ncf_sf fix).
  const maxSteps = Math.max(500, Math.ceil(8 * Math.sqrt(halfLam + 1)));

  function cdfTerm(j) {
    return gammainc(k / 2 + j, x / 2);
  }

  let logPMode = -halfLam + (jMode > 0 ? jMode * Math.log(halfLam) - gammaln(jMode + 1) : 0);
  let pTerm = Math.exp(logPMode);
  let sum = pTerm * cdfTerm(jMode);

  let pUp = pTerm;
  for (let j = jMode + 1; j < jMode + maxSteps; j++) {
    pUp *= halfLam / j;
    const contrib = pUp * cdfTerm(j);
    sum += contrib;
    if (j > jMode + 5 && pUp < 1e-14) break;
  }

  let pDown = pTerm;
  for (let j = jMode - 1; j >= 0; j--) {
    pDown *= (j + 1) / halfLam;
    const contrib = pDown * cdfTerm(j);
    sum += contrib;
    if (jMode - j > 5 && pDown < 1e-14) break;
  }

  return Math.min(1, Math.max(0, sum));
}

// ── 2. Generic helpers ──────────────────────────────────────────────────────

// Generic bisection solver: find x in [lo, hi] such that fn(x) ≈ target.
// Assumes fn is monotone non-decreasing. Returns NaN if target is not
// bracketed — this is intentional: silent clamping to a bracket boundary
// would let downstream code use a number that isn't actually a root. All
// existing callers are responsible for expanding hi (or shrinking lo)
// before delegating to bisect when their target might fall outside.
function bisect(fn, target, lo, hi, tol = 1e-6, maxIter = 200) {
  if (fn(lo) > target || fn(hi) < target) return NaN;
  for (let i = 0; i < maxIter; i++) {
    const mid = (lo + hi) / 2;
    if (fn(mid) < target) lo = mid;
    else hi = mid;
    if (hi - lo < tol) break;
  }
  return (lo + hi) / 2;
}

// ── 2b. Power functions ─────────────────────────────────────────────────────
// Keyed by test shape, same formulas used by tools/power.tsx. Kept here so
// the StatsTile (group plot) can report achieved power and the
// n-per-group needed for 80 % power directly from the observed data.

function powerTwoSample(d, n, alpha, tails) {
  const df = 2 * n - 2;
  const delta = d * Math.sqrt(n / 2);
  const tCrit = tinv(1 - alpha / tails, df);
  if (tails === 2) return 1 - nctcdf(tCrit, df, delta) + nctcdf(-tCrit, df, delta);
  return 1 - nctcdf(tCrit, df, delta);
}

function powerPaired(d, n, alpha, tails) {
  const df = n - 1;
  const delta = d * Math.sqrt(n);
  const tCrit = tinv(1 - alpha / tails, df);
  if (tails === 2) return 1 - nctcdf(tCrit, df, delta) + nctcdf(-tCrit, df, delta);
  return 1 - nctcdf(tCrit, df, delta);
}

function powerOneSample(d, n, alpha, tails) {
  return powerPaired(d, n, alpha, tails);
}

function powerAnova(f, n, alpha, k) {
  const df1 = k - 1,
    df2 = k * (n - 1);
  if (df2 < 1) return 0;
  const lambda = n * k * f * f;
  // Central F at small df has very heavy tails — e.g. F(1, 1) only reaches
  // p = 0.955 at x = 200 — so a fixed upper bracket of 200 silently clamps
  // fCrit for α ≤ 0.045 at (df1, df2) = (1, 1). Expand the bracket until it
  // covers 1 − α (20 doublings → ~2·10⁸, comfortably beyond any realistic
  // fCrit) before delegating to bisect. bisect itself now refuses on an
  // unbracketed target, so we propagate NaN when the expansion fails.
  let hi = 200;
  for (let i = 0; i < 20 && fcdf(hi, df1, df2) < 1 - alpha; i++) hi *= 2;
  const fCrit = bisect((x) => fcdf(x, df1, df2), 1 - alpha, 0, hi);
  if (!Number.isFinite(fCrit)) return NaN;
  return ncf_sf(fCrit, df1, df2, lambda);
}

function powerCorrelation(r, n, alpha, tails) {
  const zr = Math.atanh(r);
  const se = 1 / Math.sqrt(Math.max(1, n - 3));
  const zCrit = norminv(1 - alpha / tails);
  if (tails === 2) return normcdf(Math.abs(zr) / se - zCrit) + normcdf(-Math.abs(zr) / se - zCrit);
  return normcdf(zr / se - zCrit);
}

function powerChi2(w, n, alpha, df) {
  const lambda = n * w * w;
  const chiCrit = chi2inv(1 - alpha, df);
  return 1 - ncchi2cdf(chiCrit, df, lambda);
}

// Cohen's f for ANOVA from group means + pooled within-SD.
//
// f = σ_means / σ_within, where σ_means is the **population-style** SD of
// the group means — i.e. divides by k, not (k−1) — treating the supplied
// means as the entire population of cell means rather than a sample. This
// matches Cohen (1988) and R's pwr::pwr.anova.test, which is what the
// downstream power calculator is calibrated against. Callers that have a
// sample SD of group means should multiply by √((k−1)/k) before passing
// in, or recompute from the raw means.
function fFromGroupMeans(meansArr, sd) {
  if (!meansArr.length || sd <= 0) return 0;
  const grandMean = meansArr.reduce((a, b) => a + b, 0) / meansArr.length;
  const sigmaMeans = Math.sqrt(
    meansArr.reduce((s, m) => s + (m - grandMean) * (m - grandMean), 0) / meansArr.length
  );
  return sigmaMeans / sd;
}

// ── 3. Sample helpers ───────────────────────────────────────────────────────

function sampleMean(x) {
  const n = x.length;
  if (n === 0) return NaN;
  let s = 0;
  for (let i = 0; i < n; i++) s += x[i];
  return s / n;
}

// Sample variance with (n-1) denominator (Bessel-corrected). Welford's
// online algorithm: one pass, no need to compute the mean separately, and
// numerically more robust than the naive E[X²] − E[X]² formula (which
// catastrophically cancels when the data have a large offset). The classic
// two-pass algorithm is comparable in accuracy on most inputs, but Welford
// avoids a second loop and pre-computed mean, which is cleaner and slightly
// faster on large arrays.
function sampleVariance(x) {
  const n = x.length;
  if (n < 2) return NaN;
  let mean = 0,
    M2 = 0;
  for (let i = 0; i < n; i++) {
    const d = x[i] - mean;
    mean += d / (i + 1);
    M2 += d * (x[i] - mean);
  }
  return M2 / (n - 1);
}

function sampleSD(x) {
  return Math.sqrt(sampleVariance(x));
}

// Midrank assignment with ties — returns ranks[i] = 1-based rank of x[i],
// averaging ranks for tied values. Also returns the sum of (t³−t)/12 for each
// tie group, needed as the tie-correction term in Mann-Whitney / Kruskal-Wallis.
function rankWithTies(x) {
  const n = x.length;
  const idx = x.map((v, i) => [v, i]).sort((a, b) => a[0] - b[0]);
  const ranks = new Array(n);
  let tieCorrection = 0;
  let i = 0;
  while (i < n) {
    let j = i;
    while (j + 1 < n && idx[j + 1][0] === idx[i][0]) j++;
    const avgRank = (i + j + 2) / 2; // 1-based average of ranks [i+1 .. j+1]
    for (let k = i; k <= j; k++) ranks[idx[k][1]] = avgRank;
    const t = j - i + 1;
    if (t > 1) tieCorrection += t * t * t - t;
    i = j + 1;
  }
  return { ranks, tieCorrection };
}

// ── 4. Normality: Shapiro-Wilk (Royston 1995, AS R94) ───────────────────────
//
// Algorithm AS R94 (Royston 1995), as implemented in R's stats::shapiro.test.
// Valid for 3 ≤ n ≤ 5000. Returns { W, p }.
//
// The W statistic:   W = (Σ a_i · x_(i))² / Σ (x_i − x̄)²
//
// Coefficients a_i are derived from the expected values of normal order
// statistics (approximated analytically here — exact values would require
// computing E[z_(i:n)] via numerical integration, but Royston's approximation
// is accurate to the W-statistic's precision).
//
// P-value transformation uses polynomial-in-log approximations tabulated by
// Royston for the normalizing transform of W.

function shapiroWilk(x) {
  const n = x.length;
  if (n < 3 || n > 5000) {
    return { W: NaN, p: NaN, error: "Shapiro-Wilk requires 3 ≤ n ≤ 5000" };
  }
  const sorted = [...x].sort((a, b) => a - b);

  // Expected values of normal order statistics via Blom's approximation:
  //   m_i ≈ Φ⁻¹((i − 3/8) / (n + 1/4))
  // These are the "m" vector in AS R94.
  const m = new Array(n);
  for (let i = 0; i < n; i++) {
    m[i] = norminv((i + 1 - 3 / 8) / (n + 1 / 4));
  }
  let mm = 0;
  for (let i = 0; i < n; i++) mm += m[i] * m[i];

  // Coefficients a_i (Royston 1992 analytical form, AS R94).
  // For i = n:    a_n   = −2.706056 u⁵ + 4.434685 u⁴ − 2.071190 u³
  //                       − 0.147981 u² + 0.221157 u + m_n / √mm
  // For i = n−1:  a_{n−1} = −3.582633 u⁵ + 5.682633 u⁴ − 1.752460 u³
  //                         − 0.293762 u² + 0.042981 u + m_{n−1} / √mm
  // where u = 1/√n. Middle coefficients follow AS R94's epsilon correction.
  const a = new Array(n);
  const u = 1 / Math.sqrt(n);
  const sqrtMm = Math.sqrt(mm);

  if (n === 3) {
    // Exact for n = 3: a_1 = √(1/2), a_3 = −a_1, a_2 = 0.
    a[0] = -Math.SQRT1_2;
    a[1] = 0;
    a[2] = Math.SQRT1_2;
  } else {
    const an =
      m[n - 1] / sqrtMm +
      0.221157 * u -
      0.147981 * u * u -
      2.07119 * u * u * u +
      4.434685 * u * u * u * u -
      2.706056 * u * u * u * u * u;
    a[n - 1] = an;
    a[0] = -an;

    if (n >= 6) {
      const an1 =
        m[n - 2] / sqrtMm +
        0.042981 * u -
        0.293762 * u * u -
        1.75246 * u * u * u +
        5.682633 * u * u * u * u -
        3.582633 * u * u * u * u * u;
      a[n - 2] = an1;
      a[1] = -an1;

      // Epsilon correction for middle coefficients (AS R94).
      const phi =
        (mm - 2 * m[n - 1] * m[n - 1] - 2 * m[n - 2] * m[n - 2]) /
        (1 - 2 * an * an - 2 * an1 * an1);
      const sqrtPhi = Math.sqrt(phi);
      for (let i = 2; i < n - 2; i++) a[i] = m[i] / sqrtPhi;
    } else {
      // n = 4 or 5: only tail coefficients, simpler correction.
      const phi = (mm - 2 * m[n - 1] * m[n - 1]) / (1 - 2 * an * an);
      const sqrtPhi = Math.sqrt(phi);
      for (let i = 1; i < n - 1; i++) a[i] = m[i] / sqrtPhi;
    }
  }

  // W = (Σ a_i · x_(i))² / Σ (x_i − x̄)²
  let xbar = 0;
  for (let i = 0; i < n; i++) xbar += sorted[i];
  xbar /= n;
  let num = 0,
    den = 0;
  for (let i = 0; i < n; i++) {
    num += a[i] * sorted[i];
    const d = sorted[i] - xbar;
    den += d * d;
  }
  if (den === 0) return { W: NaN, p: NaN, error: "Zero variance" };
  // Clamp to [0, 1] — floating-point can produce W = 1 + ε for a perfect
  // linear sample (e.g. n=3 [1,2,3]), which would break asin(√W) below.
  const W = Math.max(0, Math.min(1, (num * num) / den));

  // P-value via Royston 1995 normalizing transform.
  let p;
  if (n === 3) {
    // Exact distribution at n=3: p = 6 · (asin(√W) − asin(√(3/4))) / π
    const pi6 = 6 / Math.PI;
    const stqr = Math.asin(Math.sqrt(3 / 4));
    p = pi6 * (Math.asin(Math.sqrt(W)) - stqr);
    if (p < 0) p = 0;
    if (p > 1) p = 1;
  } else if (n <= 11) {
    // Polynomial in n for gamma and mu, log-transform on (gamma − ln(1−W)).
    const gamma = -2.273 + 0.459 * n;
    const mu = 0.544 - 0.39978 * n + 0.025054 * n * n - 0.0006714 * n * n * n;
    const sigma = Math.exp(1.3822 - 0.77857 * n + 0.062767 * n * n - 0.0020322 * n * n * n);
    const y = -Math.log(gamma - Math.log(1 - W));
    const z = (y - mu) / sigma;
    p = 1 - normcdf(z);
  } else {
    // n ≥ 12: log(1−W) is approximately normal after transform.
    const lnN = Math.log(n);
    const mu = -1.5861 - 0.31082 * lnN - 0.083751 * lnN * lnN + 0.0038915 * lnN * lnN * lnN;
    const sigma = Math.exp(-0.4803 - 0.082676 * lnN + 0.0030302 * lnN * lnN);
    const y = Math.log(1 - W);
    const z = (y - mu) / sigma;
    p = 1 - normcdf(z);
  }

  return { W, p };
}

// ── 5. Equal-variance tests ─────────────────────────────────────────────────
//
// Brown-Forsythe variant of Levene's test (median-based — robust to
// non-normality, which is what we want in a screening step that runs before
// we've decided whether the data are normal).
//
// Algorithm: for each group compute |x_ij − median_i|, then run a one-way
// ANOVA on those absolute deviations. F statistic and p-value from the
// F-distribution.
//
// Input: groups = [[x11, x12, ...], [x21, x22, ...], ...]
// Output: { F, df1, df2, p }

function leveneTest(groups) {
  const k = groups.length;
  if (k < 2) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "≥2 groups required" };
  // Absolute deviations from the group median.
  const devs = groups.map((g) => {
    const s = [...g].sort((a, b) => a - b);
    const n = s.length;
    const med = n % 2 === 0 ? (s[n / 2 - 1] + s[n / 2]) / 2 : s[Math.floor(n / 2)];
    return g.map((v) => Math.abs(v - med));
  });
  // One-way ANOVA on deviations.
  let Ntot = 0;
  let grandSum = 0;
  for (const d of devs) {
    Ntot += d.length;
    for (const v of d) grandSum += v;
  }
  if (Ntot <= k) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "Not enough observations" };
  const grandMean = grandSum / Ntot;
  let ssBetween = 0,
    ssWithin = 0;
  for (const d of devs) {
    const n = d.length;
    if (n === 0) continue;
    let s = 0;
    for (const v of d) s += v;
    const m = s / n;
    ssBetween += n * (m - grandMean) * (m - grandMean);
    for (const v of d) ssWithin += (v - m) * (v - m);
  }
  const df1 = k - 1;
  const df2 = Ntot - k;
  if (ssWithin === 0) {
    // All groups are internally constant → within-group dispersion is zero
    // and Levene's F is undefined (0/0 at best, a phantom ∞ at worst).
    // R's equivalent oneway.test on the deviations reports F = NaN / p = NA.
    return {
      F: NaN,
      df1,
      df2,
      p: NaN,
      error: "Data are essentially constant (zero within-group dispersion)",
    };
  }
  const F = ssBetween / df1 / (ssWithin / df2);
  const p = 1 - fcdf(F, df1, df2);
  return { F, df1, df2, p };
}

// ── 6. Two-sample location tests ────────────────────────────────────────────
//
// tTest(x, y, { equalVar }) — two-sample t-test.
//   equalVar=true  → Student's t (pooled variance, df = n1+n2−2)
//   equalVar=false → Welch's t (unequal variance, Welch-Satterthwaite df)
// Two-sided p-value. Returns { t, df, p, mean1, mean2, ... }.

function tTest(x, y, opts = {}) {
  const equalVar = opts.equalVar !== false;
  const n1 = x.length,
    n2 = y.length;
  if (n1 < 2 || n2 < 2) {
    return { t: NaN, df: 0, p: NaN, error: "Each group needs n≥2" };
  }
  const m1 = sampleMean(x),
    m2 = sampleMean(y);
  const v1 = sampleVariance(x),
    v2 = sampleVariance(y);
  // Degenerate case: both groups constant. Matches R, which refuses with
  // "data are essentially constant" — any result here would have NaN df
  // (Welch) or zero SE (Student), neither of which is meaningful.
  if (v1 === 0 && v2 === 0) {
    return {
      t: NaN,
      df: NaN,
      p: NaN,
      mean1: m1,
      mean2: m2,
      var1: v1,
      var2: v2,
      n1,
      n2,
      error: "Data are essentially constant (zero variance in both groups)",
    };
  }
  let t, df;
  if (equalVar) {
    const sp2 = ((n1 - 1) * v1 + (n2 - 1) * v2) / (n1 + n2 - 2);
    const se = Math.sqrt(sp2 * (1 / n1 + 1 / n2));
    t = (m1 - m2) / se;
    df = n1 + n2 - 2;
  } else {
    const se = Math.sqrt(v1 / n1 + v2 / n2);
    t = (m1 - m2) / se;
    const num = (v1 / n1 + v2 / n2) ** 2;
    const den = (v1 / n1) ** 2 / (n1 - 1) + (v2 / n2) ** 2 / (n2 - 1);
    df = num / den;
  }
  // Two-sided p
  const p = 2 * (1 - tcdf(Math.abs(t), df));
  return { t, df, p, mean1: m1, mean2: m2, var1: v1, var2: v2, n1, n2 };
}

// Mann-Whitney U test (two-sided) — ranks with midranks for ties, normal
// approximation with continuity correction and tie correction to σ_U².
// Matches R's wilcox.test(x, y, exact=FALSE, correct=TRUE) when there are
// ties or larger samples; R switches to an exact enumerator when n1*n2<50
// and there are no ties — we note this in comments but stick to normal
// approximation here (the error vs exact is <0.01 in p even for small n).
//
// Returns { U, U1, U2, z, p, n1, n2 }. U = min(U1, U2).

function mannWhitneyU(x, y) {
  const n1 = x.length,
    n2 = y.length;
  if (n1 < 1 || n2 < 1) return { U: NaN, z: NaN, p: NaN, error: "Empty group" };
  const all = x.concat(y);
  const { ranks, tieCorrection } = rankWithTies(all);
  let R1 = 0;
  for (let i = 0; i < n1; i++) R1 += ranks[i];
  const U1 = R1 - (n1 * (n1 + 1)) / 2;
  const U2 = n1 * n2 - U1;
  const U = Math.min(U1, U2);
  const N = n1 + n2;
  const muU = (n1 * n2) / 2;
  // σ_U² with tie correction (Lehmann 1975):
  //  σ² = n1·n2/12 · [(N+1) − Σ(t³−t) / (N(N−1))]
  const sigma2 = ((n1 * n2) / 12) * (N + 1 - tieCorrection / (N * (N - 1)));
  const sigmaU = Math.sqrt(sigma2);
  // Continuity-corrected z (matches wilcox.test correct=TRUE).
  // Shift U toward the mean by 0.5.
  const diff = U1 - muU;
  let z;
  if (sigmaU === 0) z = 0;
  else if (diff > 0) z = (diff - 0.5) / sigmaU;
  else if (diff < 0) z = (diff + 0.5) / sigmaU;
  else z = 0;
  const p = 2 * (1 - normcdf(Math.abs(z)));
  return { U, U1, U2, z, p, n1, n2 };
}

// ── 7. Two-sample effect sizes ──────────────────────────────────────────────
//
// Cohen's d — standardized mean difference using pooled SD (Bessel-corrected).
// Hedges' g — small-sample bias-corrected version of Cohen's d.
// rankBiserial — non-parametric effect size paired with Mann-Whitney U.

function cohenD(x, y) {
  const n1 = x.length,
    n2 = y.length;
  if (n1 < 2 || n2 < 2) return NaN;
  const m1 = sampleMean(x),
    m2 = sampleMean(y);
  const v1 = sampleVariance(x),
    v2 = sampleVariance(y);
  const sp2 = ((n1 - 1) * v1 + (n2 - 1) * v2) / (n1 + n2 - 2);
  // Pooled SD is zero → effect size is undefined (±Infinity is misleading).
  if (sp2 === 0) return NaN;
  return (m1 - m2) / Math.sqrt(sp2);
}

function hedgesG(x, y) {
  const d = cohenD(x, y);
  if (!Number.isFinite(d)) return d;
  const df = x.length + y.length - 2;
  if (df < 1) return NaN;
  // Exact small-sample correction factor:
  //   J(df) = Γ(df/2) / (Γ((df−1)/2) · √(df/2))
  // computed in log space via gammaln to avoid Γ overflow at large df.
  // The familiar `J ≈ 1 − 3/(4n − 9)` shortcut is the leading term of the
  // asymptotic expansion; it's off by ~0.3% at the smallest practical
  // sample (n1 = n2 = 3) and converges to the exact form by n ≈ 30.
  // Tightening this also matches what `effectsize::hedges_g()` reports.
  const J = Math.exp(gammaln(df / 2) - gammaln((df - 1) / 2) - 0.5 * Math.log(df / 2));
  return d * J;
}

// Rank-biserial correlation from Mann-Whitney U (Kerby 2014).
// r = 1 − 2U/(n1·n2). Sign follows U1 vs U2 (positive means x tends to rank
// higher than y).
function rankBiserial(U1, n1, n2) {
  if (n1 * n2 === 0) return NaN;
  return 1 - (2 * U1) / (n1 * n2);
}

// ── 8. k-sample location tests ──────────────────────────────────────────────
//
// Input for all three is `groups` — an array of numeric arrays.

// One-way ANOVA (equal variances assumed).
// Returns { F, df1, df2, p, ssBetween, ssWithin, grandMean }.
function oneWayANOVA(groups) {
  const k = groups.length;
  if (k < 2) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "≥2 groups required" };
  let Ntot = 0;
  let grandSum = 0;
  for (const g of groups) {
    Ntot += g.length;
    for (const v of g) grandSum += v;
  }
  if (Ntot <= k) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "Not enough observations" };
  const grandMean = grandSum / Ntot;
  let ssBetween = 0,
    ssWithin = 0;
  for (const g of groups) {
    const n = g.length;
    if (n === 0) continue;
    let s = 0;
    for (const v of g) s += v;
    const m = s / n;
    ssBetween += n * (m - grandMean) * (m - grandMean);
    for (const v of g) ssWithin += (v - m) * (v - m);
  }
  const df1 = k - 1;
  const df2 = Ntot - k;
  if (ssWithin === 0) {
    // Every group is internally constant. R's oneway.test returns F = Inf
    // with p < 2.2e-16, but that's misleading in a UI — the "significance"
    // is a divide-by-zero artefact, not evidence of a real location shift.
    // Mirror the tTest convention and refuse.
    return {
      F: NaN,
      df1,
      df2,
      p: NaN,
      ssBetween,
      ssWithin,
      grandMean,
      error: "Data are essentially constant (zero within-group dispersion)",
    };
  }
  const F = ssBetween / df1 / (ssWithin / df2);
  const p = 1 - fcdf(F, df1, df2);
  return { F, df1, df2, p, ssBetween, ssWithin, grandMean };
}

// Welch's ANOVA (unequal variances).
// Follows R's oneway.test(var.equal=FALSE) source:
//   w_i = n_i / s_i²,  W = Σ w_i,  m = Σ(w_i · mean_i)/W
//   num = Σ w_i (mean_i − m)² / (k − 1)
//   h   = Σ (1 − w_i/W)² / (n_i − 1)
//   den = 1 + 2(k − 2)/(k² − 1) · h
//   F   = num/den,  df1 = k−1,  df2 = (k² − 1) / (3 h)
function welchANOVA(groups) {
  const k = groups.length;
  if (k < 2) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "≥2 groups required" };
  const ns = groups.map((g) => g.length);
  if (ns.some((n) => n < 2)) {
    return { F: NaN, df1: 0, df2: 0, p: NaN, error: "Each group needs n≥2" };
  }
  const means = groups.map(sampleMean);
  const vars = groups.map(sampleVariance);
  // Welch weights are n_i / s_i² — any zero-variance group makes its weight
  // infinite and poisons the whole computation (matches R oneway.test's
  // F = NaN, p = NA on constant data).
  if (vars.some((v) => v === 0)) {
    return {
      F: NaN,
      df1: k - 1,
      df2: NaN,
      p: NaN,
      error: "Data are essentially constant (zero variance in at least one group)",
    };
  }
  const w = vars.map((v, i) => ns[i] / v);
  const Wsum = w.reduce((a, b) => a + b, 0);
  const m = w.reduce((a, wi, i) => a + wi * means[i], 0) / Wsum;
  let num = 0;
  for (let i = 0; i < k; i++) num += w[i] * (means[i] - m) * (means[i] - m);
  num /= k - 1;
  let h = 0;
  for (let i = 0; i < k; i++) {
    const term = 1 - w[i] / Wsum;
    h += (term * term) / (ns[i] - 1);
  }
  const den = 1 + ((2 * (k - 2)) / (k * k - 1)) * h;
  const F = num / den;
  const df1 = k - 1;
  const df2 = (k * k - 1) / (3 * h);
  const p = 1 - fcdf(F, df1, df2);
  return { F, df1, df2, p };
}

// Kruskal-Wallis H test with tie correction.
//   H = (12/(N(N+1))) · Σ (R_i²/n_i) − 3(N+1)
//   H' = H / (1 − Σ(t³−t)/(N³−N))       [tie-corrected]
//   df = k − 1
//   p  = 1 − χ²_df(H')
function kruskalWallis(groups) {
  const k = groups.length;
  if (k < 2) return { H: NaN, df: 0, p: NaN, error: "≥2 groups required" };
  // Concatenate, remember group membership, rank together.
  const all = [];
  const owner = [];
  for (let i = 0; i < k; i++) {
    for (const v of groups[i]) {
      all.push(v);
      owner.push(i);
    }
  }
  const N = all.length;
  if (N <= k) return { H: NaN, df: 0, p: NaN, error: "Not enough observations" };
  // All values identical → ranks are all (N+1)/2, H computes to 0/0, and the
  // tie-correction denominator C = 1 − (N³−N)/(N³−N) = 0. The naive code path
  // skipped the divide and reported H=0, p=1 — a "no difference detected"
  // answer that masks the fact that the test is undefined. Match R's
  // kruskal.test behavior (it warns and returns NaN) by detecting the
  // all-tied case explicitly and surfacing an error the stats tile picks up.
  let allTied = true;
  for (let i = 1; i < N; i++) {
    if (all[i] !== all[0]) {
      allTied = false;
      break;
    }
  }
  if (allTied) {
    return { H: NaN, df: k - 1, p: NaN, error: "Data are essentially constant" };
  }
  const { ranks, tieCorrection } = rankWithTies(all);
  // Sum of ranks per group.
  const R = new Array(k).fill(0);
  for (let i = 0; i < N; i++) R[owner[i]] += ranks[i];
  let sumR2n = 0;
  for (let i = 0; i < k; i++) sumR2n += (R[i] * R[i]) / groups[i].length;
  let H = (12 / (N * (N + 1))) * sumR2n - 3 * (N + 1);
  // Tie correction (Siegel & Castellan): divide H by C.
  const C = 1 - tieCorrection / (N * N * N - N);
  if (C > 0) H /= C;
  const df = k - 1;
  const p = 1 - chi2cdf(H, df);
  return { H, df, p };
}

// ── 9. k-sample effect sizes ────────────────────────────────────────────────

// η² = SSbetween / SStotal (ANOVA).
function etaSquared(groups) {
  const a = oneWayANOVA(groups);
  if (a.error) return NaN;
  const ssTotal = a.ssBetween + a.ssWithin;
  return ssTotal === 0 ? 0 : a.ssBetween / ssTotal;
}

// ε² = H / (N − 1)  — Kruskal-Wallis effect size (Tomczak & Tomczak 2014).
function epsilonSquared(groups) {
  const kw = kruskalWallis(groups);
  if (kw.error) return NaN;
  let N = 0;
  for (const g of groups) N += g.length;
  return N > 1 ? kw.H / (N - 1) : NaN;
}

// ── 10. Studentized range distribution ─────────────────────────────────────
//
// The CDF of the studentized range Q (k means, ν error df) is
//
//   P(Q ≤ q) = ∫₀^∞ f_S(s) · P(R ≤ q·s) ds
//
// where S = √(χ²_ν/ν) and R is the range of k independent standard normals.
// The range CDF itself is
//
//   P(R ≤ w) = ∫_{−∞}^{∞} k · φ(u) · [Φ(u+w) − Φ(u)]^{k−1} du
//
// Both integrals are handled by the cached 48-point Gauss-Legendre rule.
// Matches R's `ptukey` to ~5 decimal places on the cases we benchmark.

// P(range of k standard normals ≤ w)
function _wprob(w, k) {
  if (w <= 0) return 0;
  const gl = _gaussLegendre(48);
  // Truncate at ±8σ — φ is negligible beyond.
  const lo = -8,
    hi = 8;
  const half = (hi - lo) / 2,
    mid = (hi + lo) / 2;
  const invSqrt2Pi = 1 / Math.sqrt(2 * Math.PI);
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const u = mid + half * gl.nodes[i];
    const phiU = invSqrt2Pi * Math.exp(-0.5 * u * u);
    const diff = normcdf(u + w) - normcdf(u);
    if (diff <= 0) continue;
    const term = k * phiU * Math.pow(diff, k - 1);
    sum += half * gl.weights[i] * term;
  }
  return Math.max(0, Math.min(1, sum));
}

// P(Q ≤ q | k groups, df error degrees of freedom)
//
// Substitute y = log(s) — integrate f_S(e^y)·e^y dy. Integration bounds
// [yLo, yHi] are set by the chi² quantiles so the support is exactly where
// the mass lives. This keeps the 48 Gauss-Legendre nodes concentrated on the
// peak regardless of df (a fixed s = u/(1−u) map leaks nodes into the
// exponential tail at high df, saturating ptukey well below 1).
function ptukey(q, k, df) {
  if (q <= 0) return 0;
  if (k < 2 || df < 1) return NaN;
  const gl = _gaussLegendre(48);
  // S = √(χ²_ν / ν). Bound y = log(S) via chi² quantiles at ±1e-10.
  const chiLo = chi2inv(1e-10, df);
  const chiHi = chi2inv(1 - 1e-10, df);
  const yLo = 0.5 * Math.log(Math.max(chiLo, 1e-300) / df);
  const yHi = 0.5 * Math.log(chiHi / df);
  const halfDf = df / 2;
  const logConst = Math.log(2) + halfDf * Math.log(halfDf) - gammaln(halfDf);
  const halfW = (yHi - yLo) / 2;
  const midW = (yHi + yLo) / 2;
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const y = midW + halfW * gl.nodes[i];
    const s = Math.exp(y);
    // f_S(s) · ds = 2·(ν/2)^(ν/2)/Γ(ν/2) · s^(ν−1) · exp(−ν·s²/2) · s dy
    const logFS = logConst + df * y - (df * s * s) / 2;
    const fSds = Math.exp(logFS);
    if (!Number.isFinite(fSds) || fSds === 0) continue;
    sum += halfW * gl.weights[i] * fSds * _wprob(q * s, k);
  }
  return Math.max(0, Math.min(1, sum));
}

// Inverse of the studentized range CDF: find q such that ptukey(q, k, df) = p.
// Historically this called bisect(…, 0.01, 100) with a fixed upper bracket,
// which clamped silently for extreme inputs (e.g. k = 50, df = 1, p = 0.999).
// Now expands the upper bracket by doubling until it covers p, then bisects
// with a relative-tolerance termination so the precision is consistent
// regardless of the answer's magnitude. Returns NaN when the expansion
// cannot bracket p — matches R qtukey's NaN-with-warning behavior at
// pathological inputs rather than returning a stale bracket boundary.
function qtukey(p, k, df) {
  if (p <= 0) return 0;
  if (p >= 1) return Infinity;
  if (k < 2 || df < 1) return NaN;
  let lo = 0.01,
    hi = 100;
  // 20 doublings cap hi at ~10⁸ — more than enough for any realistic
  // (k, df, α) combo; anything larger is pathological and deserves NaN.
  for (let i = 0; i < 20 && ptukey(hi, k, df) < p; i++) {
    lo = hi;
    hi *= 2;
  }
  if (ptukey(hi, k, df) < p) return NaN;
  for (let i = 0; i < 200; i++) {
    const mid = (lo + hi) / 2;
    if (ptukey(mid, k, df) < p) lo = mid;
    else hi = mid;
    if (hi - lo < 1e-7 * (Math.abs(lo) + 1)) break;
  }
  return (lo + hi) / 2;
}

// ── 11. Post-hoc tests ──────────────────────────────────────────────────────

// Tukey HSD — all pairwise comparisons following one-way ANOVA.
// Uses Tukey-Kramer for unbalanced designs.
//   q_ij = |m_i − m_j| / √(MSE · (1/n_i + 1/n_j) / 2)
//   p_ij = 1 − ptukey(q_ij, k, df_error)
//   CI half-width = qtukey(1−α, k, df_error) · √(MSE · (1/n_i + 1/n_j) / 2)
// Returns { pairs: [{ i, j, diff, se, q, p, lwr, upr }], k, df }
function tukeyHSD(groups, opts = {}) {
  const alpha = opts.alpha != null ? opts.alpha : 0.05;
  const k = groups.length;
  if (k < 2) return { pairs: [], error: "≥2 groups required" };
  const anova = oneWayANOVA(groups);
  if (anova.error) return { pairs: [], error: anova.error };
  const dfErr = anova.df2;
  const mse = anova.ssWithin / dfErr;
  // Degenerate case: every group is perfectly constant → MSE=0 → division
  // by zero in q. Refuse rather than emit Infinity q / zero p-values.
  if (mse === 0) {
    return {
      pairs: [],
      k,
      df: dfErr,
      mse,
      error: "Cannot compute Tukey HSD — zero within-group variance (data essentially constant)",
    };
  }
  const means = groups.map(sampleMean);
  const ns = groups.map((g) => g.length);
  const qCrit = qtukey(1 - alpha, k, dfErr);
  const pairs = [];
  for (let i = 0; i < k - 1; i++) {
    for (let j = i + 1; j < k; j++) {
      const diff = means[j] - means[i];
      const se = Math.sqrt((mse * (1 / ns[i] + 1 / ns[j])) / 2);
      const q = Math.abs(diff) / se;
      const p = 1 - ptukey(q, k, dfErr);
      const margin = qCrit * se;
      pairs.push({
        i,
        j,
        diff,
        se,
        q,
        p,
        lwr: diff - margin,
        upr: diff + margin,
      });
    }
  }
  return { pairs, k, df: dfErr, mse };
}

// Games-Howell — post-hoc for Welch's ANOVA. Uses Welch-Satterthwaite df
// per pair and the studentized range distribution.
//   se_ij = √(s_i²/n_i + s_j²/n_j)
//   q     = (m_i − m_j) / √(se²/2)  … Tukey form, see Day & Quinn 1989
//   df    = (s_i²/n_i + s_j²/n_j)² / ((s_i²/n_i)²/(n_i−1) + (s_j²/n_j)²/(n_j−1))
//   p     = 1 − ptukey(|q|, k, df)
// Returns { pairs: [{ i, j, diff, se, q, df, p }], k }
function gamesHowell(groups) {
  const k = groups.length;
  if (k < 2) return { pairs: [], error: "≥2 groups required" };
  const means = groups.map(sampleMean);
  const vars = groups.map(sampleVariance);
  const ns = groups.map((g) => g.length);
  // Degenerate case: if any group has zero variance, pairs that touch it
  // produce SE=0 (when both sides are zero) or NaN df in the Welch-
  // Satterthwaite formula — ptukey then propagates NaN into p-values.
  // Refuse at the top level rather than return a mix of valid and NaN pairs,
  // which would quietly corrupt compact-letter displays downstream.
  if (vars.some((v) => v === 0)) {
    return {
      pairs: [],
      k,
      error: "Cannot compute Games-Howell — at least one group has zero variance",
    };
  }
  const pairs = [];
  for (let i = 0; i < k - 1; i++) {
    for (let j = i + 1; j < k; j++) {
      const vi = vars[i] / ns[i];
      const vj = vars[j] / ns[j];
      const se = Math.sqrt(vi + vj);
      const diff = means[j] - means[i];
      // Tukey-form q using SE/√2 (consistent with TukeyHSD's SE convention).
      const q = Math.abs(diff) / (se / Math.SQRT2);
      const num = (vi + vj) * (vi + vj);
      const den = (vi * vi) / (ns[i] - 1) + (vj * vj) / (ns[j] - 1);
      const df = num / den;
      const p = 1 - ptukey(q, k, df);
      pairs.push({ i, j, diff, se, q, df, p });
    }
  }
  return { pairs, k };
}

// Benjamini-Hochberg adjusted p-values.
// Sort p-values ascending, compute p_(i) · m/i, then enforce monotonicity
// from largest down, and finally cap at 1.
function bhAdjust(ps) {
  const m = ps.length;
  const order = ps.map((p, i) => [p, i]).sort((a, b) => a[0] - b[0]);
  const adj = new Array(m);
  let running = 1;
  for (let rank = m; rank >= 1; rank--) {
    const [p, origIdx] = order[rank - 1];
    const q = (p * m) / rank;
    running = Math.min(running, q);
    adj[origIdx] = Math.min(1, running);
  }
  return adj;
}

// Dunn's test — pairwise rank-based post-hoc following Kruskal-Wallis.
// Uses the *global* rank sums with midranks and tie correction (Siegel
// & Castellan 1988). Z-statistic, two-sided normal p-values, BH-adjusted.
//
//   z_ij = (R_i/n_i − R_j/n_j) / √(σ² · (1/n_i + 1/n_j))
//   σ²   = (N(N+1)/12 − Σ(t³−t)/(12(N−1)))
//   p    = 2 · (1 − Φ(|z|))
// Returns { pairs: [{ i, j, z, p, pAdj }], method }
function dunnTest(groups) {
  const k = groups.length;
  if (k < 2) return { pairs: [], error: "≥2 groups required" };
  const all = [];
  const owner = [];
  for (let i = 0; i < k; i++) {
    for (const v of groups[i]) {
      all.push(v);
      owner.push(i);
    }
  }
  const N = all.length;
  const { ranks, tieCorrection } = rankWithTies(all);
  const meanR = new Array(k).fill(0);
  const ns = groups.map((g) => g.length);
  const sumR = new Array(k).fill(0);
  for (let idx = 0; idx < N; idx++) sumR[owner[idx]] += ranks[idx];
  for (let i = 0; i < k; i++) meanR[i] = sumR[i] / ns[i];
  // Tie-corrected variance term (Dunn 1964 with Siegel-Castellan fix):
  //   σ² = (N(N+1)/12 − (Σ(t³−t)) / (12·(N−1)))
  const sigma2 = (N * (N + 1)) / 12 - tieCorrection / (12 * (N - 1));
  const rawPs = [];
  const pairs = [];
  for (let i = 0; i < k - 1; i++) {
    for (let j = i + 1; j < k; j++) {
      const se = Math.sqrt(sigma2 * (1 / ns[i] + 1 / ns[j]));
      const z = (meanR[i] - meanR[j]) / se;
      const p = 2 * (1 - normcdf(Math.abs(z)));
      pairs.push({ i, j, z, p });
      rawPs.push(p);
    }
  }
  const adj = bhAdjust(rawPs);
  for (let i = 0; i < pairs.length; i++) pairs[i].pAdj = adj[i];
  return { pairs, method: "Benjamini-Hochberg" };
}

// ── 12. Compact letter display ──────────────────────────────────────────────
//
// Piepho 2004 "An Algorithm for a Letter-Based Representation of
// All-Pairwise Comparisons". Given pairwise significance (p < α), assign
// letters to groups such that any two groups sharing at least one letter
// are NOT significantly different.
//
// Input:  pairs = [{ i, j, p }], k groups total, alpha
// Output: array of k strings — each group's letter label, e.g. ["a", "ab", "b"]
//
// Algorithm (insert-and-absorb):
//  1. Start with one letter containing all groups.
//  2. For every significant pair (i, j): split any letter containing both
//     i and j into two letters — one drops i, the other drops j.
//  3. Remove any letter that is a subset of another (absorb).
//  4. Letters are labeled "a", "b", "c"... by order of first appearance.
function compactLetterDisplay(pairs, k, alpha = 0.05) {
  if (k <= 0) return [];
  // Sets of groups, each set = one letter.
  let letters = [new Set(Array.from({ length: k }, (_, i) => i))];
  for (const pr of pairs) {
    const p = pr.pAdj != null ? pr.pAdj : pr.p;
    // Guard NaN explicitly: `NaN >= alpha` is false, so without this the loop
    // would treat any unresolved pair as "significant" and start splitting
    // letters on noise — corrupting the entire CLD silently. NaN p-values
    // arise when an upstream test (tTest, Tukey, etc.) returns an error; we
    // skip them rather than guess, matching R's multcompView::multcompLetters
    // which also requires non-NA inputs.
    if (!Number.isFinite(p) || p >= alpha) continue;
    const { i, j } = pr;
    const newLetters = [];
    for (const L of letters) {
      if (L.has(i) && L.has(j)) {
        const L1 = new Set(L);
        L1.delete(i);
        const L2 = new Set(L);
        L2.delete(j);
        if (L1.size > 0) newLetters.push(L1);
        if (L2.size > 0) newLetters.push(L2);
      } else {
        newLetters.push(L);
      }
    }
    // Absorb: drop any letter that is a strict subset of another.
    const filtered = [];
    for (const L of newLetters) {
      let absorbed = false;
      for (const M of newLetters) {
        if (L === M) continue;
        if (L.size < M.size) {
          let sub = true;
          for (const v of L) {
            if (!M.has(v)) {
              sub = false;
              break;
            }
          }
          if (sub) {
            absorbed = true;
            break;
          }
        }
      }
      if (!absorbed && !filtered.some((F) => F.size === L.size && [...F].every((v) => L.has(v)))) {
        filtered.push(L);
      }
    }
    letters = filtered;
  }
  // Assign labels in order of first group-index each letter contains.
  letters.sort((A, B) => Math.min(...A) - Math.min(...B));
  const labels = "abcdefghijklmnopqrstuvwxyz";
  const out = Array.from({ length: k }, () => "");
  for (let li = 0; li < letters.length; li++) {
    const lbl = labels[li] || `[${li}]`;
    for (const g of letters[li]) out[g] += lbl;
  }
  return out;
}

// ── 13. Automatic test selection ────────────────────────────────────────────
//
// Runs the assumption checks and walks the decision tree the UI will offer
// as the default pick (user can still override). Per-group Shapiro-Wilk for
// normality, Brown-Forsythe Levene for homogeneity of variance, then:
//
//   k = 2:
//     any group non-normal  → Mann-Whitney U  (no post-hoc)
//     equal variance        → Student's t     (no post-hoc)
//     unequal variance      → Welch's t       (no post-hoc)
//
//   k ≥ 3:
//     any group non-normal  → Kruskal-Wallis + Dunn (BH)
//     equal variance        → one-way ANOVA + Tukey HSD
//     unequal variance      → Welch's ANOVA + Games-Howell
//
// Thresholds default to α = 0.05 for both assumption checks; caller can pass
// `{ alphaNormality, alphaVariance }` to override. When a group has n < 3
// Shapiro-Wilk can't run — we treat normality as unknown and conservatively
// recommend the rank-based test.
//
// **Caveat on per-group Shapiro-Wilk at α = 0.05:** running Shapiro on each
// of k groups inflates the family-wise false-positive rate to roughly
// 1 − (1 − α)^k. With k = 5 groups the chance of falsely declaring at least
// one group "non-normal" is ~23 % even when all five are perfectly normal,
// which biases this auto-selector toward Kruskal-Wallis. ANOVA is robust to
// modest non-normality, so this conservative bias is by design — but users
// who already know their data are normal can loosen `alphaNormality` (e.g.
// 0.01) to reduce the inflation, or override the test pick directly. R's
// pooled approach would be to test the residuals of the fitted model rather
// than each group separately; we don't do that here because the auto-pick
// is an entry-point heuristic, not a publication-grade decision rule.
function selectTest(groups, opts = {}) {
  const alphaN = opts.alphaNormality != null ? opts.alphaNormality : 0.05;
  const alphaV = opts.alphaVariance != null ? opts.alphaVariance : 0.05;
  const k = groups.length;
  if (k < 2) {
    return { error: "≥2 groups required", k };
  }

  const normality = groups.map((g, i) => {
    if (g.length < 3) {
      return { group: i, n: g.length, W: null, p: null, normal: null, note: "n<3" };
    }
    const sw = shapiroWilk(g);
    if (sw.error) {
      return { group: i, n: g.length, W: null, p: null, normal: null, note: sw.error };
    }
    return { group: i, n: g.length, W: sw.W, p: sw.p, normal: sw.p >= alphaN };
  });
  const allKnownNormal = normality.every((r) => r.normal === true);
  const anyNonNormal = normality.some((r) => r.normal === false || r.normal === null);

  const lev = leveneTest(groups);
  const equalVar = lev.error ? null : lev.p >= alphaV;

  let test, postHoc, reason;
  if (anyNonNormal || !allKnownNormal) {
    if (k === 2) {
      test = "mannWhitney";
      postHoc = null;
      reason = "At least one group is not normally distributed (Shapiro-Wilk p < α).";
    } else {
      test = "kruskalWallis";
      postHoc = "dunn";
      reason = "At least one group is not normally distributed (Shapiro-Wilk p < α).";
    }
  } else if (equalVar === false) {
    if (k === 2) {
      test = "welchT";
      postHoc = null;
      reason = "Groups are normal but variances differ (Levene p < α).";
    } else {
      test = "welchANOVA";
      postHoc = "gamesHowell";
      reason = "Groups are normal but variances differ (Levene p < α).";
    }
  } else {
    if (k === 2) {
      test = "studentT";
      postHoc = null;
      reason = "Both groups are normal with equal variance.";
    } else {
      test = "oneWayANOVA";
      postHoc = "tukeyHSD";
      reason = "All groups are normal with equal variance.";
    }
  }

  return {
    k,
    normality,
    allNormal: allKnownNormal,
    levene: lev.error
      ? { error: lev.error }
      : { F: lev.F, df1: lev.df1, df2: lev.df2, p: lev.p, equalVar },
    recommendation: { test, postHoc, reason },
  };
}

// Map a p-value to the 4-level significance stars used on plots.
// Non-finite or missing p → empty string so callers can suppress the label.
function pStars(p) {
  if (!Number.isFinite(p)) return "";
  if (p < 0.0001) return "****";
  if (p < 0.001) return "***";
  if (p < 0.01) return "**";
  if (p < 0.05) return "*";
  return "ns";
}

// Format a p-value for display next to a test statistic. Uses scientific
// notation below 1e-3 (where fixed-point would round to 0) and keeps 3
// significant digits otherwise.
function formatP(p) {
  if (p == null || !Number.isFinite(p)) return "—";
  if (p < 1e-4) return p.toExponential(1);
  if (p < 1e-3) return p.toExponential(2);
  return p.toFixed(4);
}

// ── 14. Hierarchical clustering ─────────────────────────────────────────────

// Pairwise row-wise distance matrix for a 2-D numeric array.
// metric: "euclidean" | "manhattan" | "correlation" (1 − Pearson r).
// NaN cells are ignored pairwise (only rows' shared finite columns contribute).
// Returns an N×N symmetric array of distances (0 on the diagonal).
function pairwiseDistance(matrix, metric) {
  const n = matrix.length;
  const D = Array.from({ length: n }, () => new Array(n).fill(0));
  for (let i = 0; i < n; i++) {
    for (let j = i + 1; j < n; j++) {
      const d = rowDistance(matrix[i], matrix[j], metric);
      D[i][j] = d;
      D[j][i] = d;
    }
  }
  return D;
}

function rowDistance(a, b, metric) {
  const n = Math.min(a.length, b.length);
  const xs = [];
  const ys = [];
  for (let k = 0; k < n; k++) {
    if (Number.isFinite(a[k]) && Number.isFinite(b[k])) {
      xs.push(a[k]);
      ys.push(b[k]);
    }
  }
  if (xs.length === 0) return NaN;
  if (metric === "manhattan") {
    let s = 0;
    for (let k = 0; k < xs.length; k++) s += Math.abs(xs[k] - ys[k]);
    return s;
  }
  if (metric === "correlation") {
    // 1 − Pearson correlation; collapses to 0 for identical vectors,
    // 2 for perfectly anti-correlated ones.
    if (xs.length < 2) return NaN;
    let mx = 0,
      my = 0;
    for (let k = 0; k < xs.length; k++) {
      mx += xs[k];
      my += ys[k];
    }
    mx /= xs.length;
    my /= xs.length;
    let sxy = 0,
      sxx = 0,
      syy = 0;
    for (let k = 0; k < xs.length; k++) {
      const dx = xs[k] - mx;
      const dy = ys[k] - my;
      sxy += dx * dy;
      sxx += dx * dx;
      syy += dy * dy;
    }
    if (sxx === 0 || syy === 0) return 1;
    return 1 - sxy / Math.sqrt(sxx * syy);
  }
  // euclidean (default)
  let s = 0;
  for (let k = 0; k < xs.length; k++) {
    const d = xs[k] - ys[k];
    s += d * d;
  }
  return Math.sqrt(s);
}

// Agglomerative hierarchical clustering. Naive O(n³) merge loop — clear,
// easy to verify, adequate for the ≤500-leaf range the heatmap tool targets.
// linkage: "average" (UPGMA) | "complete" | "single".
// Returns { tree, order }:
//   tree — nested { index, left, right, height, size }; leaves have index ≥ 0
//          and left/right null; internal nodes have index = -1.
//   order — array of leaf indices in dendrogram left-to-right order.
function hclust(distMatrix, linkage) {
  const n = distMatrix.length;
  if (n === 0) return { tree: null, order: [] };
  if (n === 1)
    return { tree: { index: 0, left: null, right: null, height: 0, size: 1 }, order: [0] };

  // Working copies: active cluster metadata + mutable distance matrix.
  const clusters = new Array(n);
  const D = new Array(n);
  for (let i = 0; i < n; i++) {
    clusters[i] = { index: i, left: null, right: null, height: 0, size: 1 };
    D[i] = distMatrix[i].slice();
  }
  const active = new Set();
  for (let i = 0; i < n; i++) active.add(i);

  const mergeFn =
    linkage === "complete"
      ? (d1, d2) => Math.max(d1, d2)
      : linkage === "single"
        ? (d1, d2) => Math.min(d1, d2)
        : null; // signals UPGMA (size-weighted average)

  while (active.size > 1) {
    // Find the closest pair among active clusters.
    let best = Infinity;
    let bi = -1,
      bj = -1;
    const act = Array.from(active);
    for (let ai = 0; ai < act.length; ai++) {
      for (let aj = ai + 1; aj < act.length; aj++) {
        const i = act[ai],
          j = act[aj];
        const d = D[i][j];
        if (Number.isFinite(d) && d < best) {
          best = d;
          bi = i;
          bj = j;
        }
      }
    }
    if (bi < 0) {
      // No finite distances remain — happens when rows have no overlap
      // in finite values (e.g. correlation on a matrix where most cells
      // are NaN). Force-merge the two lowest-index active clusters at a
      // sentinel height so the returned tree still covers every leaf,
      // instead of silently truncating to the first active singleton.
      bi = act[0];
      bj = act[1];
      best = 0;
    }

    // Merge j into i — the new cluster keeps index bi, bj becomes inactive.
    const merged = {
      index: -1,
      left: clusters[bi],
      right: clusters[bj],
      height: best,
      size: clusters[bi].size + clusters[bj].size,
    };
    const sizeI = clusters[bi].size;
    const sizeJ = clusters[bj].size;

    active.delete(bj);
    for (const k of active) {
      if (k === bi) continue;
      const dik = D[bi][k];
      const djk = D[bj][k];
      let nd;
      if (mergeFn) {
        nd = mergeFn(dik, djk);
      } else {
        // UPGMA: weighted average by cluster size.
        nd = (sizeI * dik + sizeJ * djk) / (sizeI + sizeJ);
      }
      D[bi][k] = nd;
      D[k][bi] = nd;
    }
    clusters[bi] = merged;
  }

  const rootId = Array.from(active)[0];
  const tree = clusters[rootId];

  // Leaf order by in-order traversal.
  const order = [];
  (function walk(node) {
    if (!node) return;
    if (node.left === null && node.right === null) {
      order.push(node.index);
    } else {
      walk(node.left);
      walk(node.right);
    }
  })(tree);

  return { tree, order };
}

// Flatten a hclust tree into SVG-friendly L-shaped segments.
// Each leaf is placed at integer x = position-in-order; internal nodes
// at the mean of their subtree leaves' positions. Returns:
//   { segments, maxHeight }
// where segments is an array of { x1, y1, x2, y2 } in DATA space
// (y = merge height, 0 at leaves). The caller scales x, y into pixels.
function dendrogramLayout(tree) {
  if (!tree) return { segments: [], maxHeight: 0 };
  const segments = [];
  let maxHeight = 0;
  function place(node) {
    if (node.left === null && node.right === null) {
      return { x: node._leafPos, h: 0 };
    }
    const L = place(node.left);
    const R = place(node.right);
    const h = node.height;
    if (h > maxHeight) maxHeight = h;
    // Vertical stems from each child up to the merge height.
    segments.push({ x1: L.x, y1: L.h, x2: L.x, y2: h });
    segments.push({ x1: R.x, y1: R.h, x2: R.x, y2: h });
    // Horizontal bar joining them.
    segments.push({ x1: L.x, y1: h, x2: R.x, y2: h });
    return { x: (L.x + R.x) / 2, h };
  }
  // Annotate leaves with their left-to-right position.
  let leafIdx = 0;
  (function num(node) {
    if (!node) return;
    if (node.left === null && node.right === null) {
      node._leafPos = leafIdx++;
    } else {
      num(node.left);
      num(node.right);
    }
  })(tree);
  place(tree);
  return { segments, maxHeight };
}

// ── 15. K-means (non-hierarchical) clustering ───────────────────────────────

// K-means with k-means++ seeded init. Rows of `matrix` are the observations;
// columns are features. Missing values (NaN) are handled pairwise per-feature
// when computing squared distances, and are skipped when averaging centroids.
// opts: { seed=1, maxIter=100, restarts=8 } — `restarts` independent runs
// from different seeded inits; the lowest-inertia run is returned.
// Returns { clusters, centroids, inertia, iterations, order }:
//   clusters   — array of length n with cluster id (0..k-1) per row
//   centroids  — k × d array (NaN if a feature had no finite values in a cluster)
//   inertia    — sum of squared distances from each row to its centroid
//   iterations — iterations the winning restart took to converge
//   order      — row-index permutation: rows grouped by cluster id, within each
//                cluster sorted by distance-to-centroid ascending. Clusters
//                themselves are ordered by cluster-id.
function kmeans(matrix, k, opts) {
  const options = opts || {};
  const seed = options.seed != null ? options.seed : 1;
  const maxIter = options.maxIter != null ? options.maxIter : 100;
  const restarts = options.restarts != null ? options.restarts : 8;
  const n = matrix.length;
  if (n === 0) return { clusters: [], centroids: [], inertia: 0, iterations: 0, order: [] };
  const d = matrix[0].length;
  const kEff = Math.max(1, Math.min(k, n));

  const baseRng = kmeansRng(seed);
  let best = null;
  for (let r = 0; r < restarts; r++) {
    const rng = kmeansRng(Math.floor(baseRng() * 2147483646) + 1);
    const attempt = kmeansOnce(matrix, kEff, d, rng, maxIter);
    if (!best || attempt.inertia < best.inertia) best = attempt;
  }

  // Within-cluster ordering by distance to centroid (ascending).
  const distToCentroid = new Array(n);
  for (let i = 0; i < n; i++) {
    distToCentroid[i] = sqDistPartial(matrix[i], best.centroids[best.clusters[i]]);
  }
  const order = [];
  for (let c = 0; c < kEff; c++) {
    const members = [];
    for (let i = 0; i < n; i++) if (best.clusters[i] === c) members.push(i);
    members.sort((a, b) => distToCentroid[a] - distToCentroid[b]);
    for (const m of members) order.push(m);
  }

  return {
    clusters: best.clusters,
    centroids: best.centroids,
    inertia: best.inertia,
    iterations: best.iterations,
    order,
  };
}

function kmeansOnce(matrix, k, d, rng, maxIter) {
  const n = matrix.length;
  const centroids = kmeansPlusPlusInit(matrix, k, rng);
  const clusters = new Array(n).fill(0);

  let iterations = 0;
  for (let iter = 0; iter < maxIter; iter++) {
    iterations = iter + 1;
    let changed = false;
    for (let i = 0; i < n; i++) {
      let best = 0;
      let bestD = sqDistPartial(matrix[i], centroids[0]);
      for (let c = 1; c < k; c++) {
        const dist = sqDistPartial(matrix[i], centroids[c]);
        if (dist < bestD) {
          bestD = dist;
          best = c;
        }
      }
      if (clusters[i] !== best) {
        clusters[i] = best;
        changed = true;
      }
    }

    // Recompute centroids as per-feature means over finite values.
    const sums = Array.from({ length: k }, () => new Array(d).fill(0));
    const counts = Array.from({ length: k }, () => new Array(d).fill(0));
    const clusterSizes = new Array(k).fill(0);
    for (let i = 0; i < n; i++) {
      const c = clusters[i];
      clusterSizes[c]++;
      for (let j = 0; j < d; j++) {
        const v = matrix[i][j];
        if (Number.isFinite(v)) {
          sums[c][j] += v;
          counts[c][j]++;
        }
      }
    }
    for (let c = 0; c < k; c++) {
      if (clusterSizes[c] === 0) {
        // Empty cluster: reseed to the row farthest from its current centroid.
        let worst = -1;
        let worstD = -Infinity;
        for (let i = 0; i < n; i++) {
          const dist = sqDistPartial(matrix[i], centroids[clusters[i]]);
          if (dist > worstD) {
            worstD = dist;
            worst = i;
          }
        }
        if (worst >= 0) {
          for (let j = 0; j < d; j++) centroids[c][j] = matrix[worst][j];
          clusters[worst] = c;
          changed = true;
        }
        continue;
      }
      for (let j = 0; j < d; j++) {
        centroids[c][j] = counts[c][j] > 0 ? sums[c][j] / counts[c][j] : NaN;
      }
    }
    if (!changed) break;
  }

  let inertia = 0;
  for (let i = 0; i < n; i++) inertia += sqDistPartial(matrix[i], centroids[clusters[i]]);

  return { clusters, centroids, inertia, iterations };
}

function kmeansPlusPlusInit(matrix, k, rng) {
  const n = matrix.length;
  const d = matrix[0].length;
  const centroids = [];
  const first = Math.floor(rng() * n);
  centroids.push(matrix[first].slice());

  const dists = new Array(n).fill(Infinity);
  for (let c = 1; c < k; c++) {
    let total = 0;
    for (let i = 0; i < n; i++) {
      const dist = sqDistPartial(matrix[i], centroids[c - 1]);
      if (dist < dists[i]) dists[i] = dist;
      if (Number.isFinite(dists[i])) total += dists[i];
    }
    if (total <= 0 || !Number.isFinite(total)) {
      // Degenerate: fall back to a random distinct-ish row.
      let pick = Math.floor(rng() * n);
      centroids.push(matrix[pick].slice());
      continue;
    }
    let target = rng() * total;
    let pick = 0;
    for (let i = 0; i < n; i++) {
      if (!Number.isFinite(dists[i])) continue;
      target -= dists[i];
      if (target <= 0) {
        pick = i;
        break;
      }
      pick = i;
    }
    centroids.push(matrix[pick].slice());
  }
  // Ensure every centroid has length d (for rows that had trailing NaN columns).
  for (const c of centroids) {
    while (c.length < d) c.push(NaN);
  }
  return centroids;
}

// Park-Miller LCG — kept local so stats.js has no cross-file dependency.
function kmeansRng(seed) {
  let s = seed % 2147483647;
  if (s <= 0) s += 2147483646;
  return () => {
    s = (s * 16807) % 2147483647;
    return s / 2147483647;
  };
}

function sqDistPartial(row, centroid) {
  const n = Math.min(row.length, centroid.length);
  let s = 0;
  let any = false;
  for (let k = 0; k < n; k++) {
    const a = row[k];
    const b = centroid[k];
    if (Number.isFinite(a) && Number.isFinite(b)) {
      const diff = a - b;
      s += diff * diff;
      any = true;
    }
  }
  return any ? s : Infinity;
}

// ──────────────────────────────────────────────────────────────────
// shared-color-input.js
// ──────────────────────────────────────────────────────────────────
// shared-color-input.js — plain JS, no JSX
// Requires React to be loaded globally before this script.

// Accepts #rgb or #rrggbb (case-insensitive); returns lowercased #rrggbb
// or null if the string is not a valid hex color.
function normalizeHexColor(v) {
  if (typeof v !== "string") return null;
  if (/^#[0-9a-fA-F]{6}$/.test(v)) return v.toLowerCase();
  if (/^#[0-9a-fA-F]{3}$/.test(v)) {
    const s = v.toLowerCase();
    return "#" + s[1] + s[1] + s[2] + s[2] + s[3] + s[3];
  }
  return null;
}

function ColorInput({ value, onChange, size = 22 }) {
  const [text, setText] = React.useState(value);
  // Only sync local text from parent `value` when the current text doesn't
  // already normalise to that value. Without this guard, typing `#abc` would
  // commit `#aabbcc` upstream, which round-trips back through this effect and
  // rewrites the text field to the 6-char form mid-keystroke — the cursor
  // jumps and the user's `#abc` shorthand gets auto-expanded against their
  // will. With the guard, external value changes (preset swap, palette reset)
  // still sync, but self-commits don't clobber what the user typed.
  React.useEffect(() => {
    if (normalizeHexColor(text) !== value) setText(value);
  }, [value]);
  const commit = (v) => {
    const n = normalizeHexColor(v);
    if (n) onChange(n);
  };
  return React.createElement(
    "div",
    { style: { display: "flex", alignItems: "center", gap: 4 } },
    React.createElement("input", {
      type: "color",
      value: value,
      onChange: (e) => onChange(e.target.value),
      style: {
        width: size,
        height: size,
        border: "1px solid var(--border-strong)",
        borderRadius: 4,
        cursor: "pointer",
        padding: 0,
        flexShrink: 0,
      },
    }),
    React.createElement("input", {
      type: "text",
      value: text,
      onChange: (e) => {
        setText(e.target.value);
        commit(e.target.value);
      },
      onBlur: (e) => {
        const n = normalizeHexColor(e.target.value);
        if (n) onChange(n);
        else setText(value);
      },
      maxLength: 7,
      spellCheck: false,
      style: {
        width: 64,
        fontFamily: "monospace",
        fontSize: 11,
        border: "1px solid var(--border-strong)",
        borderRadius: 4,
        padding: "2px 5px",
        color: "var(--text)",
        background: "var(--surface)",
      },
    })
  );
}

// ──────────────────────────────────────────────────────────────────
// shared-file-drop.js
// ──────────────────────────────────────────────────────────────────
// shared-file-drop.js — plain JS, no JSX
// Requires React to be loaded globally before this script.

const FILE_LIMIT_BYTES = 2 * 1024 * 1024; // 2 MB — hard reject
const FILE_WARN_BYTES = 1 * 1024 * 1024; // 1 MB — show warning but allow

function FileDropZone({
  onFileLoad,
  accept = ".csv,.tsv,.txt,.dat",
  hint = "CSV · TSV · TXT · DAT — 2 MB max",
}) {
  const [drag, setDrag] = React.useState(false);
  const [focus, setFocus] = React.useState(false);
  const [sizeError, setSizeError] = React.useState(null);
  const [sizeWarn, setSizeWarn] = React.useState(null);
  const inputRef = React.useRef();

  const handle = (file) => {
    setSizeError(null);
    setSizeWarn(null);
    if (file.size > FILE_LIMIT_BYTES) {
      setSizeError(
        `File too large (${(file.size / 1024 / 1024).toFixed(1)} MB). Maximum is 2 MB — split the file or sample rows and try again.`
      );
      return;
    }
    if (file.size > FILE_WARN_BYTES) {
      setSizeWarn(
        `Large file (${(file.size / 1024 / 1024).toFixed(1)} MB) — parsing may take a moment.`
      );
    }
    const reader = new FileReader();
    reader.onload = (e) => onFileLoad(e.target.result, file.name);
    reader.readAsText(file);
  };

  const openPicker = () => inputRef.current && inputRef.current.click();

  return React.createElement(
    "div",
    null,
    React.createElement(
      "div",
      {
        role: "button",
        tabIndex: 0,
        "aria-label": "Drop a data file here or press Enter to browse",
        onDragOver: (e) => {
          e.preventDefault();
          setDrag(true);
        },
        onDragLeave: () => setDrag(false),
        onDrop: (e) => {
          e.preventDefault();
          setDrag(false);
          if (e.dataTransfer.files[0]) handle(e.dataTransfer.files[0]);
        },
        onClick: openPicker,
        onKeyDown: (e) => {
          if (e.key === "Enter" || e.key === " ") {
            e.preventDefault();
            openPicker();
          }
        },
        onFocus: () => setFocus(true),
        onBlur: () => setFocus(false),
        style: {
          border: `2px dashed ${drag ? "var(--accent-primary)" : sizeError ? "var(--danger-text)" : "var(--text-faint)"}`,
          borderRadius: 12,
          padding: "48px 24px",
          textAlign: "center",
          cursor: "pointer",
          background: drag
            ? "var(--accent-primary-weak)"
            : sizeError
              ? "rgba(239,68,68,0.04)"
              : "transparent",
          transition: "all .2s",
          outline: focus ? "2px solid var(--accent-primary)" : "none",
          outlineOffset: 2,
        },
      },
      React.createElement("input", {
        ref: inputRef,
        type: "file",
        accept: accept,
        hidden: true,
        onChange: (e) => {
          if (e.target.files[0]) handle(e.target.files[0]);
          e.target.value = "";
        },
      }),
      React.createElement(
        "div",
        { style: { fontSize: 40, marginBottom: 8 }, "aria-hidden": "true" },
        "📂"
      ),
      React.createElement(
        "p",
        { style: { margin: 0, fontSize: 15, color: "var(--text-muted)" } },
        "Drop CSV, TSV, or TXT — or click to browse"
      ),
      React.createElement(
        "p",
        { style: { margin: "4px 0 0", fontSize: 12, color: "var(--text-faint)" } },
        hint
      )
    ),
    sizeError &&
      React.createElement(
        "div",
        {
          role: "alert",
          style: {
            marginTop: 10,
            padding: "10px 14px",
            borderRadius: 8,
            background: "var(--danger-bg)",
            border: "1px solid var(--danger-border)",
            display: "flex",
            alignItems: "center",
            gap: 8,
          },
        },
        React.createElement("span", { style: { fontSize: 16 }, "aria-hidden": "true" }, "🚫"),
        React.createElement(
          "span",
          { style: { fontSize: 12, color: "var(--danger-text)", fontWeight: 600 } },
          sizeError
        )
      ),
    sizeWarn &&
      React.createElement(
        "div",
        {
          role: "status",
          style: {
            marginTop: 10,
            padding: "10px 14px",
            borderRadius: 8,
            background: "var(--warning-bg)",
            border: "1px solid var(--warning-border)",
            display: "flex",
            alignItems: "center",
            gap: 8,
          },
        },
        React.createElement("span", { style: { fontSize: 16 }, "aria-hidden": "true" }, "⚠️"),
        React.createElement(
          "span",
          { style: { fontSize: 12, color: "var(--warning-text)" } },
          sizeWarn
        )
      )
  );
}

// ──────────────────────────────────────────────────────────────────
// shared-svg-legend.js
// ──────────────────────────────────────────────────────────────────
// shared-svg-legend.js — plain JS, no JSX
// Requires React to be loaded globally before this script.

// ── SVG Legend helpers ────────────────────────────────────────────────────────

// itemWidth: number (fixed) or function(block) => number (dynamic per block)
function computeLegendHeight(blocks, usableW, itemWidth) {
  if (!blocks || !blocks.length) return 0;
  const IH = 18,
    TH = 15;
  const iw = itemWidth || 88;
  let t = 10;
  blocks.forEach(function (b, bi) {
    if (b.title) t += TH;
    if (b.items) {
      const bIW = typeof iw === "function" ? iw(b) : iw;
      t += Math.ceil(b.items.length / Math.max(1, Math.floor(usableW / bIW))) * IH;
    }
    if (b.gradient) t += 30;
    if (b.sizeItems && b.sizeItems.length) {
      const mr = Math.max(
        ...b.sizeItems.map(function (i) {
          return i.r;
        }),
        3
      );
      const rowH = mr * 2 + 4;
      // Compute per-item widths and wrap into rows
      let cx = 0,
        rows = 1;
      b.sizeItems.forEach(function (item, ii) {
        const labelW = (item.label || "").length * 5.6 + 6;
        const itemW = mr * 2 + 4 + labelW + 12;
        if (ii > 0 && cx + itemW > usableW) {
          rows++;
          cx = 0;
        }
        cx += itemW;
      });
      t += rows * rowH;
    }
    if (bi < blocks.length - 1) t += 8;
  });
  return t + 6;
}

// Renders SVG legend blocks. Returns array of <g> elements.
// startY: y offset for the first block, leftX: x offset, usableW: available width
// itemWidth: number or function(block) => number
// truncateLabel: optional max char length for labels (falsy = no truncation)
function renderSvgLegend(blocks, startY, leftX, usableW, itemWidth, truncateLabel) {
  if (!blocks || !blocks.length) return null;
  const h = React.createElement;
  const IH = 18,
    TH = 15;
  const iw = itemWidth || 88;

  // Pre-compute block Y offsets in a single pass (avoids O(n²) slice+reduce)
  const blockOffsets = [0];
  for (let bi = 0; bi < blocks.length - 1; bi++) {
    const b = blocks[bi];
    let off = blockOffsets[bi];
    if (b.title) off += TH;
    if (b.items) {
      const w = typeof iw === "function" ? iw(b) : iw;
      off += Math.ceil(b.items.length / Math.max(1, Math.floor(usableW / w))) * IH;
    }
    if (b.gradient) off += 30;
    if (b.sizeItems && b.sizeItems.length) {
      const mr = Math.max(
        ...b.sizeItems
          .map(function (i) {
            return i.r;
          })
          .concat([3])
      );
      off += mr * 2 + 4;
    }
    off += 8;
    blockOffsets.push(off);
  }

  const blockGroups = blocks.map(function (block, bi) {
    const bIW = typeof iw === "function" ? iw(block) : iw;
    const blockY = startY + blockOffsets[bi];
    const itemsPerRow = Math.max(1, Math.floor(usableW / bIW));
    const children = [];

    // Title
    if (block.title) {
      children.push(
        h(
          "text",
          { key: "title", fontSize: "10", fill: "#666", fontFamily: "sans-serif", y: 10 },
          block.title
        )
      );
    }

    // Items (circles or lines)
    if (block.items) {
      block.items.forEach(function (item, ii) {
        const row = Math.floor(ii / itemsPerRow);
        const col = ii % itemsPerRow;
        let label = item.label || "";
        if (truncateLabel && label.length > truncateLabel)
          label = label.slice(0, truncateLabel - 2) + "\u2026";
        let shape;
        if (item.shape === "line") {
          shape = h("line", {
            key: "s",
            x1: 0,
            x2: 14,
            y1: 7,
            y2: 7,
            stroke: item.color,
            strokeWidth: "2.5",
          });
        } else if (item.shape === "triangle") {
          shape = h("polygon", { key: "s", points: "6,1 1,12 11,12", fill: item.color });
        } else if (item.shape === "square") {
          shape = h("rect", { key: "s", x: 1, y: 2, width: 10, height: 10, fill: item.color });
        } else if (item.shape === "cross") {
          shape = h("path", {
            key: "s",
            d: "M4,0 H8 V4 H12 V8 H8 V12 H4 V8 H0 V4 H4 Z",
            fill: item.color,
          });
        } else {
          shape = h("circle", { key: "s", cx: 6, cy: 7, r: 5, fill: item.color });
        }
        const text = h(
          "text",
          {
            key: "t",
            x: item.shape === "line" ? 18 : 14,
            y: 11,
            fontSize: "10",
            fill: "#444",
            fontFamily: "sans-serif",
          },
          label
        );
        children.push(
          h(
            "g",
            {
              key: "i" + ii,
              transform:
                "translate(" + col * bIW + ", " + ((block.title ? TH : 0) + row * IH) + ")",
            },
            shape,
            text
          )
        );
      });
    }

    // Gradient
    if (block.gradient) {
      const gw = Math.min(usableW * 0.6, 200),
        gh = 12;
      const th = block.title ? TH : 0;
      const gradId = "svggrad-" + bi;
      const stops = block.gradient.stops.map(function (c, si) {
        return h("stop", {
          key: si,
          offset: (si / (block.gradient.stops.length - 1)) * 100 + "%",
          stopColor: c,
        });
      });
      children.push(
        h(
          "g",
          { key: "grad", transform: "translate(0, " + th + ")" },
          h(
            "defs",
            null,
            h("linearGradient", { id: gradId, x1: "0%", y1: "0%", x2: "100%", y2: "0%" }, stops)
          ),
          h("rect", { x: 0, y: 0, width: gw, height: gh, fill: "url(#" + gradId + ")", rx: "2" }),
          h(
            "text",
            {
              x: 0,
              y: gh + 13,
              fontSize: "9",
              fill: "#555",
              fontFamily: "sans-serif",
              textAnchor: "start",
            },
            block.gradient.min
          ),
          h(
            "text",
            {
              x: gw,
              y: gh + 13,
              fontSize: "9",
              fill: "#555",
              fontFamily: "sans-serif",
              textAnchor: "end",
            },
            block.gradient.max
          )
        )
      );
    }

    // Size items (scatter) — label-aware spacing with row wrapping
    if (block.sizeItems && block.sizeItems.length) {
      const sth = block.title ? TH : 0;
      const maxR = Math.max(
        ...block.sizeItems.map(function (i) {
          return i.r;
        }),
        3
      );
      const rowH = maxR * 2 + 4;
      let cx = 0,
        row = 0;
      const sizeChildren = block.sizeItems.map(function (item, ii) {
        const labelW = (item.label || "").length * 5.6 + 6;
        const itemW = maxR * 2 + 4 + labelW + 12;
        if (ii > 0 && cx + itemW > usableW) {
          row++;
          cx = 0;
        }
        const tx = cx;
        cx += itemW;
        return h(
          "g",
          { key: ii, transform: "translate(" + tx + ", " + row * rowH + ")" },
          h("circle", {
            cx: maxR,
            cy: 0,
            r: item.r,
            fill: "#888",
            fillOpacity: "0.35",
            stroke: "#888",
            strokeWidth: "0.8",
          }),
          h(
            "text",
            { x: maxR * 2 + 4, y: 4, fontSize: "9", fill: "#444", fontFamily: "sans-serif" },
            item.label
          )
        );
      });
      children.push(
        h("g", { key: "size", transform: "translate(0, " + (sth + maxR) + ")" }, sizeChildren)
      );
    }

    const blockId =
      block.id ||
      (block.title && typeof svgSafeId === "function"
        ? "legend-" + svgSafeId(block.title)
        : "legend-block-" + bi);
    return h(
      "g",
      {
        key: bi,
        id: blockId,
        transform: "translate(" + leftX + ", " + blockY + ")",
      },
      children
    );
  });
  return h("g", { id: "legend" }, blockGroups);
}

// ──────────────────────────────────────────────────────────────────
// shared-core.js
// ──────────────────────────────────────────────────────────────────
// shared-core.js — plain JS, no JSX
// Requires React, shared.js, and components.css (dv-btn classes) to be loaded
// globally before this script.

// ── Data Preview Table ──────────────────────────────────────────────────────

function DataPreview({ headers, rows, maxRows }) {
  const limit = maxRows || 10;
  const d = rows.slice(0, limit);
  return React.createElement(
    "div",
    {
      style: {
        overflowX: "auto",
        fontSize: 11,
        border: "1px solid var(--border)",
        borderRadius: 6,
      },
    },
    React.createElement(
      "table",
      { style: { borderCollapse: "collapse", width: "100%", minWidth: 400 } },
      React.createElement(
        "thead",
        null,
        React.createElement(
          "tr",
          { style: { background: "var(--surface-sunken)" } },
          React.createElement(
            "th",
            {
              style: {
                padding: "5px 8px",
                border: "1px solid var(--border)",
                color: "var(--text-faint)",
                fontSize: 10,
              },
            },
            "#"
          ),
          ...headers.map((h, i) =>
            React.createElement(
              "th",
              {
                key: i,
                style: {
                  padding: "5px 8px",
                  border: "1px solid var(--border)",
                  color: "var(--text)",
                  fontWeight: 600,
                },
              },
              h
            )
          )
        )
      ),
      React.createElement(
        "tbody",
        null,
        ...d.map((r, ri) =>
          React.createElement(
            "tr",
            { key: ri },
            React.createElement(
              "td",
              {
                style: {
                  padding: "3px 8px",
                  border: "1px solid var(--border)",
                  color: "var(--text-faint)",
                  fontSize: 10,
                },
              },
              ri + 1
            ),
            ...r.map((v, ci) =>
              React.createElement(
                "td",
                {
                  key: ci,
                  style: {
                    padding: "3px 8px",
                    border: "1px solid var(--border)",
                    color: "var(--text-muted)",
                  },
                },
                v
              )
            )
          )
        )
      )
    ),
    rows.length > limit
      ? React.createElement(
          "p",
          {
            style: {
              padding: 6,
              fontSize: 11,
              color: "var(--text-faint)",
              textAlign: "center",
            },
          },
          `… ${rows.length - limit} more (${rows.length} total)`
        )
      : null
  );
}

// ── Error Boundary ──────────────────────────────────────────────────────────

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { error: null, info: null };
  }
  static getDerivedStateFromError(error) {
    return { error: error };
  }
  componentDidCatch(error, info) {
    this.setState({ info: info });
    if (typeof console !== "undefined" && console.error) {
      console.error("Tool crashed:", error, info);
    }
  }
  render() {
    if (!this.state.error) return this.props.children;
    const err = this.state.error;
    const info = this.state.info;
    const msg = err && err.message ? err.message : String(err);
    const stack = err && err.stack ? err.stack : msg;
    const compStack = info && info.componentStack ? info.componentStack : "";
    const details = stack + (compStack ? "\n\nComponent stack:" + compStack : "");
    const reload = () => {
      if (typeof window !== "undefined" && window.location) window.location.reload();
    };
    const copy = () => {
      if (typeof navigator !== "undefined" && navigator.clipboard) {
        navigator.clipboard.writeText(details).catch(() => {});
      }
    };
    const toolName = this.props.toolName || "This tool";
    return React.createElement(
      "div",
      {
        role: "alert",
        style: {
          maxWidth: 720,
          margin: "40px auto",
          padding: 24,
          fontFamily: "system-ui, -apple-system, sans-serif",
          color: "var(--text)",
        },
      },
      React.createElement(
        "h2",
        { style: { marginTop: 0, color: "var(--danger-text)", fontSize: 20 } },
        "Something went wrong"
      ),
      React.createElement(
        "p",
        { style: { fontSize: 14, lineHeight: 1.5 } },
        toolName +
          " hit an unexpected error and can't continue. Your data is still on your machine — nothing was sent anywhere. Try reloading; if it keeps crashing, use \u201cCopy error details\u201d and open an issue."
      ),
      React.createElement(
        "pre",
        {
          style: {
            background: "var(--danger-bg)",
            border: "1px solid var(--danger-border)",
            borderRadius: 6,
            padding: 12,
            fontSize: 12,
            color: "var(--danger-text)",
            overflow: "auto",
            maxHeight: 200,
            whiteSpace: "pre-wrap",
            wordBreak: "break-word",
          },
        },
        msg
      ),
      React.createElement(
        "details",
        { style: { marginBottom: 16 } },
        React.createElement(
          "summary",
          { style: { cursor: "pointer", fontSize: 13, color: "var(--text-muted)" } },
          "Technical details"
        ),
        React.createElement(
          "pre",
          {
            style: {
              background: "var(--surface-subtle)",
              border: "1px solid var(--border)",
              borderRadius: 6,
              padding: 12,
              fontSize: 11,
              color: "var(--text-muted)",
              overflow: "auto",
              maxHeight: 300,
              whiteSpace: "pre-wrap",
              wordBreak: "break-word",
              marginTop: 8,
            },
          },
          details
        )
      ),
      React.createElement(
        "div",
        { style: { display: "flex", gap: 10, flexWrap: "wrap" } },
        React.createElement(
          "button",
          { type: "button", onClick: reload, className: "dv-btn dv-btn-primary" },
          "Reload tool"
        ),
        React.createElement(
          "button",
          { type: "button", onClick: copy, className: "dv-btn dv-btn-secondary" },
          "Copy error details"
        )
      )
    );
  }
}

// ──────────────────────────────────────────────────────────────────
// shared-ui.js
// ──────────────────────────────────────────────────────────────────
// shared-ui.js — plain JS, no JSX
// Requires React, shared.js (toolIcon, flashSaved), components.css (dv-*
// classes), and shared-file-drop.js (FileDropZone) to be loaded globally
// before this script.

// ── Shared UI Components ─────────────────────────────────────────────────────

// NumberInput — compact numeric entry with −/+ buttons on either side
// replacing the native stacked spinner. Mimics the native <input type=
// "number"> API: `value`, `onChange(e)` where `e.target.value` is a string,
// plus `min`, `max`, `step`, `disabled`, `placeholder`, `className`, `style`,
// `inputStyle`. The −/+ buttons fire a synthetic event with the next value
// as a string so existing `(e) => setX(e.target.value)` handlers keep working.
//
// Press-and-hold: the button repeats at an accelerating cadence for as long
// as the pointer is held (first bump immediate, 400 ms before repeat kicks
// in, then 80 ms for a handful of ticks, then 40 ms). Release anywhere on
// the page stops the hold via a window-level pointerup listener, so the user
// can drag off the button mid-hold without breaking the gesture.
function NumberInput(props) {
  const value = props.value != null ? props.value : "";
  const onChange = props.onChange;
  const min = props.min != null ? Number(props.min) : null;
  const max = props.max != null ? Number(props.max) : null;
  const rawStep = props.step != null && props.step !== "any" ? Number(props.step) : 1;
  const step = isNaN(rawStep) || rawStep <= 0 ? 1 : rawStep;
  const disabled = !!props.disabled;
  const placeholder = props.placeholder;
  const className = "dv-num" + (disabled ? " dv-num-disabled" : "");

  // Hold state lives in a ref so setTimeout chains survive React re-renders
  // triggered by each fireChange. `holdRef.current` is an object per gesture:
  // { dir, next, timerId, onUp } — comparing identity in the tick lets us
  // bail out if a new hold has replaced the old one, or if stopRepeat cleared
  // it.
  const holdRef = React.useRef(null);

  const fireChange = function (newValueStr) {
    if (!onChange) return;
    onChange({ target: { value: newValueStr } });
  };

  const clamp = function (n) {
    if (min != null && n < min) n = min;
    if (max != null && n > max) n = max;
    // Round to the step's decimal precision to avoid 0.1+0.2 float noise.
    const decimals = (String(step).split(".")[1] || "").length;
    return decimals ? Number(n.toFixed(decimals)) : n;
  };

  const numericValue = Number(value);
  const minusDisabled = disabled || (min != null && !isNaN(numericValue) && numericValue <= min);
  const plusDisabled = disabled || (max != null && !isNaN(numericValue) && numericValue >= max);

  const stopRepeat = function () {
    const state = holdRef.current;
    if (!state) return;
    if (state.timerId) clearTimeout(state.timerId);
    if (state.onUp && typeof window !== "undefined") {
      window.removeEventListener("pointerup", state.onUp);
      window.removeEventListener("pointercancel", state.onUp);
    }
    holdRef.current = null;
  };

  const startRepeat = function (dir) {
    if ((dir < 0 && minusDisabled) || (dir > 0 && plusDisabled)) return;
    // Seed from the current prop value; every subsequent tick walks our own
    // ref so we stay correct even if React hasn't flushed the re-render yet.
    const seed = isNaN(Number(value)) ? (min != null ? min : 0) : Number(value);
    const state = { dir: dir, next: seed, timerId: null, onUp: null };
    holdRef.current = state;

    const doStep = function () {
      if (holdRef.current !== state) return;
      const n = clamp(state.next + dir * step);
      state.next = n;
      fireChange(String(n));
      if ((dir < 0 && min != null && n <= min) || (dir > 0 && max != null && n >= max)) {
        stopRepeat();
      }
    };

    // First step fires immediately so a quick click still bumps once.
    doStep();
    if (holdRef.current !== state) return;

    let ticks = 0;
    const tick = function () {
      if (holdRef.current !== state) return;
      doStep();
      if (holdRef.current !== state) return;
      ticks += 1;
      const delay = ticks > 8 ? 40 : 80;
      state.timerId = setTimeout(tick, delay);
    };
    // 400 ms dwell before the repeat kicks in (standard stepper feel).
    state.timerId = setTimeout(tick, 400);

    // Release anywhere on the page ends the hold — survives the user
    // dragging off the button mid-gesture.
    state.onUp = function () {
      stopRepeat();
    };
    if (typeof window !== "undefined") {
      window.addEventListener("pointerup", state.onUp);
      window.addEventListener("pointercancel", state.onUp);
    }
  };

  // Clean up if the component unmounts during a hold.
  React.useEffect(function () {
    return function () {
      stopRepeat();
    };
  }, []);

  const onMinusDown = function (e) {
    if (e.button != null && e.button !== 0) return;
    e.preventDefault();
    startRepeat(-1);
  };
  const onPlusDown = function (e) {
    if (e.button != null && e.button !== 0) return;
    e.preventDefault();
    startRepeat(1);
  };

  return React.createElement(
    "div",
    { className: className, style: props.style },
    React.createElement(
      "button",
      {
        type: "button",
        className: "dv-num-btn dv-num-btn-minus",
        onPointerDown: onMinusDown,
        disabled: minusDisabled,
        tabIndex: -1,
        "aria-label": "Decrement",
      },
      "\u2212"
    ),
    React.createElement("input", {
      type: "number",
      className: "dv-num-input",
      value: value,
      min: props.min,
      max: props.max,
      step: props.step != null ? props.step : 1,
      disabled: disabled,
      placeholder: placeholder,
      onChange: function (e) {
        fireChange(e.target.value);
      },
      style: props.inputStyle,
    }),
    React.createElement(
      "button",
      {
        type: "button",
        className: "dv-num-btn dv-num-btn-plus",
        onPointerDown: onPlusDown,
        disabled: plusDisabled,
        tabIndex: -1,
        "aria-label": "Increment",
      },
      "+"
    )
  );
}

// Slider with label + value display on top, range input below.
//
// Wrapped in React.memo with a custom comparator that intentionally ignores
// the `onChange` prop. Without this, dragging one slider re-renders every
// other slider in the same sidebar (sliders all live under the same parent
// reducer), because each call site passes an inline `onChange={(v) => updVis(
// {...})}` that gets a fresh function reference every render.
//
// Ignoring onChange is safe HERE because every call site closes the inline
// arrow over a `useReducer` dispatch (or other stable setter) plus a literal
// patch object — no captured state that could go stale between renders. If a
// future caller ever needs onChange to capture mutable state, switch back to
// React's default shallow compare and useCallback at the call sites.
function _SliderControlImpl(props) {
  const label = props.label,
    value = props.value,
    displayValue = props.displayValue,
    min = props.min,
    max = props.max,
    step = props.step,
    onChange = props.onChange;
  var dv = displayValue != null ? displayValue : value;
  var pct = ((value - min) / (max - min)) * 100;
  var grad =
    "linear-gradient(to right, var(--accent-primary) " +
    pct +
    "%, var(--slider-track) " +
    pct +
    "%)";
  return React.createElement(
    "div",
    null,
    React.createElement(
      "div",
      { style: { display: "flex", justifyContent: "space-between", marginBottom: 2 } },
      React.createElement("span", { className: "dv-label" }, label),
      React.createElement("span", { style: { fontSize: 10, color: "var(--text-faint)" } }, dv)
    ),
    React.createElement("input", {
      type: "range",
      min: min,
      max: max,
      step: step,
      value: value,
      onChange: function (e) {
        onChange(Number(e.target.value));
      },
      style: { width: "100%", background: grad },
    })
  );
}
// `var` (not `const`) so the binding lands on the script-tag global, the same
// way every other shared-*.js export does. Tools consume SliderControl as a
// global symbol; a top-level `const` would scope it to the script and break
// downstream tool .tsx files.
var SliderControl = React.memo(_SliderControlImpl, function (prev, next) {
  return (
    prev.value === next.value &&
    prev.min === next.min &&
    prev.max === next.max &&
    prev.step === next.step &&
    prev.label === next.label &&
    prev.displayValue === next.displayValue
  );
});

// Step navigation bar
function StepNavBar(props) {
  const steps = props.steps,
    currentStep = props.currentStep,
    onStepChange = props.onStepChange,
    canNavigate = props.canNavigate;
  const enabledList = steps.map(function (s) {
    return canNavigate ? canNavigate(s) : true;
  });
  const children = [];
  steps.forEach(function (s, i) {
    const enabled = enabledList[i];
    const isCurrent = currentStep === s;
    const isDoneOrCurrent = isCurrent || i < steps.indexOf(currentStep);
    children.push(
      React.createElement(
        "button",
        {
          key: "step-" + s,
          onClick: function () {
            if (enabled) onStepChange(s);
          },
          style: {
            height: 40,
            padding: "0 16px",
            borderRadius: 6,
            fontSize: 12,
            fontWeight: 600,
            background: isCurrent ? "var(--step-active-bg)" : "var(--surface)",
            color: isCurrent ? "var(--on-accent)" : enabled ? "var(--text-faint)" : "var(--border)",
            border:
              "1px solid " +
              (isCurrent
                ? "var(--step-active-border)"
                : enabled && !isDoneOrCurrent
                  ? "var(--step-ready)"
                  : enabled
                    ? "var(--border-strong)"
                    : "var(--border)"),
            boxShadow:
              enabled && !isCurrent && !isDoneOrCurrent ? "0 0 0 2px var(--step-ready)" : "none",
            cursor: enabled ? "pointer" : "default",
            fontFamily: "inherit",
            textTransform: "uppercase",
            letterSpacing: 1,
          },
        },
        i + 1 + ". " + s
      )
    );
    if (i < steps.length - 1) {
      const nextEnabled = enabledList[i + 1];
      const currentIdx = steps.indexOf(currentStep);
      const isFutureReachable = i + 1 > currentIdx && nextEnabled;
      children.push(
        React.createElement(
          "span",
          {
            key: "chev-" + s,
            "aria-hidden": "true",
            style: {
              display: "inline-flex",
              alignItems: "center",
              fontSize: 20,
              lineHeight: 1,
              fontWeight: 700,
              padding: "0 2px",
              color: isFutureReachable ? "var(--step-ready)" : "var(--border-strong)",
              transition: "color 160ms ease-out",
              userSelect: "none",
            },
          },
          "\u276F"
        )
      );
    }
  });
  return React.createElement(
    "div",
    { style: { display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center" } },
    children
  );
}

